"""
Parameterized generator for GH934_ray_43928.

Source PR:    https://github.com/ray-project/ray/pull/43928
Source Issue: https://github.com/ray-project/ray/issues/43929

Seed varies: renames 'app_details' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH934_ray_43928'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH934_ray_43928'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('app_details', 'app_details' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH934_ray_43928',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'ray-project/ray',
                "pr_number": 43928,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/ray-project/ray/pull/43928",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'python/ray/serve/_private/application_state.py': 'import logging\nimport time\nimport traceback\nfrom copy import deepcopy\nfrom dataclasses import dataclass\nfrom enum import Enum\nfrom typing import Callable, Dict, List, Optional, Tuple\n\nimport ray\nfrom ray import cloudpickle\nfrom ray._private.utils import import_attr\nfrom ray.exceptions import RuntimeEnvSetupError\nfrom ray.serve._private.common import (\n    ApplicationStatus,\n    ApplicationStatusInfo,\n    DeploymentID,\n    DeploymentStatus,\n    DeploymentStatusInfo,\n    DeploymentStatusTrigger,\n    EndpointInfo,\n    TargetCapacityDirection,\n)\nfrom ray.serve._private.config import DeploymentConfig\nfrom ray.serve._private.constants import (\n    NEW_DEFAULT_MAX_ONGOING_REQUESTS,\n    RAY_SERVE_ENABLE_TASK_EVENTS,\n    SERVE_LOGGER_NAME,\n)\nfrom ray.serve._private.deploy_utils import (\n    deploy_args_to_deployment_info,\n    get_app_code_version,\n    get_deploy_args,\n)\nfrom ray.serve._private.deployment_info import DeploymentInfo\nfrom ray.serve._private.deployment_state import DeploymentStateManager\nfrom ray.serve._private.endpoint_state import EndpointState\nfrom ray.serve._private.storage.kv_store import KVStoreBase\nfrom ray.serve._private.usage import ServeUsageTag\nfrom ray.serve._private.utils import (\n    DEFAULT,\n    check_obj_ref_ready_nowait,\n    override_runtime_envs_except_env_vars,\n)\nfrom ray.serve.config import AutoscalingConfig\nfrom ray.serve.exceptions import RayServeException\nfrom ray.serve.generated.serve_pb2 import DeploymentLanguage\nfrom ray.serve.schema import DeploymentDetails, ServeApplicationSchema\nfrom ray.types import ObjectRef\n\nlogger = logging.getLogger(SERVE_LOGGER_NAME)\n\nCHECKPOINT_KEY = "serve-application-state-checkpoint"\n\n\nclass BuildAppStatus(Enum):\n    """Status of the build application task."""\n\n    NO_TASK_IN_PROGRESS = 1\n    IN_PROGRESS = 2\n    SUCCEEDED = 3\n    FAILED = 4\n\n\n@dataclass\nclass BuildAppTaskInfo:\n    """Stores info on the current in-progress build app task.\n\n    We use a class instead of only storing the task object ref because\n    when a new config is deployed, there can be an outdated in-progress\n    build app task. We attach the code version to the task info to\n    distinguish outdated build app tasks.\n    """\n\n    obj_ref: ObjectRef\n    code_version: str\n    config: ServeApplicationSchema\n    target_capacity: Optional[float]\n    target_capacity_direction: Optional[TargetCapacityDirection]\n    finished: bool\n\n\n@dataclass\nclass ApplicationTargetState:\n    """Defines target state of application.\n\n    Target state can become inconsistent if the code version doesn\'t\n    match that of the config. When that happens, a new build app task\n    should be kicked off to reconcile the inconsistency.\n\n    deployment_infos: map of deployment name to deployment info. This is\n      - None if a config was deployed but the app hasn\'t finished\n        building yet,\n      - An empty dict if the app is deleting.\n    code_version: Code version of all deployments in target state. None\n        if application was deployed through serve.run.\n    config: application config deployed by user. None if application was\n        deployed through serve.run.\n    target_capacity: the target_capacity to use when adjusting num_replicas.\n    target_capacity_direction: the scale direction to use when\n        running the Serve autoscaler.\n    deleting: whether the application is being deleted.\n    """\n\n    deployment_infos: Optional[Dict[str, DeploymentInfo]]\n    code_version: Optional[str]\n    config: Optional[ServeApplicationSchema]\n    target_capacity: Optional[float]\n    target_capacity_direction: Optional[TargetCapacityDirection]\n    deleting: bool\n\n\nclass ApplicationState:\n    """Manage single application states with all operations"""\n\n    def __init__(\n        self,\n        name: str,\n        deployment_state_manager: DeploymentStateManager,\n        endpoint_state: EndpointState,\n        save_checkpoint_func: Callable,\n    ):\n        """\n        Args:\n            name: Application name.\n            deployment_state_manager: State manager for all deployments\n                in the cluster.\n            endpoint_state: State manager for endpoints in the system.\n            save_checkpoint_func: Function that can be called to write\n                a checkpoint of the application state. This should be\n                called in self._set_target_state() before actually\n                setting the target state so that the controller can\n                properly recover application states if it crashes.\n        """\n\n        self._name = name\n        self._status_msg = ""\n        self._deployment_state_manager = deployment_state_manager\n        self._endpoint_state = endpoint_state\n        self._route_prefix: Optional[str] = None\n        self._docs_path: Optional[str] = None\n        self._ingress_deployment_name: str = None\n\n        self._status: ApplicationStatus = ApplicationStatus.DEPLOYING\n        self._deployment_timestamp = time.time()\n\n        self._build_app_task_info: Optional[BuildAppTaskInfo] = None\n        # Before a deploy app task finishes, we don\'t know what the\n        # target deployments are, so set deployment_infos=None\n        self._target_state: ApplicationTargetState = ApplicationTargetState(\n            deployment_infos=None,\n            code_version=None,\n            config=None,\n            target_capacity=None,\n            target_capacity_direction=None,\n            deleting=False,\n        )\n        self._save_checkpoint_func = save_checkpoint_func\n\n    @property\n    def route_prefix(self) -> Optional[str]:\n        return self._route_prefix\n\n    @property\n    def docs_path(self) -> Optional[str]:\n        return self._docs_path\n\n    @property\n    def status(self) -> ApplicationStatus:\n        """Status of the application.\n\n        DEPLOYING: The build task is still running, or the deployments\n            have started deploying but aren\'t healthy yet.\n        RUNNING: All deployments are healthy.\n        DEPLOY_FAILED: The build task failed or one or more deployments\n            became unhealthy in the process of deploying\n        UNHEALTHY: While the application was running, one or more\n            deployments transition from healthy to unhealthy.\n        DELETING: Application and its deployments are being deleted.\n        """\n        return self._status\n\n    @property\n    def deployment_timestamp(self) -> int:\n        return self._deployment_timestamp\n\n    @property\n    def target_deployments(self) -> List[str]:\n        """List of target deployment names in application."""\n        if self._target_state.deployment_infos is None:\n            return []\n        return list(self._target_state.deployment_infos.keys())\n\n    @property\n    def ingress_deployment(self) -> Optional[str]:\n        return self._ingress_deployment_name\n\n    def recover_target_state_from_checkpoint(\n        self, checkpoint_data: ApplicationTargetState\n    ):\n        logger.info(\n            f"Recovering target state for application \'{self._name}\' from checkpoint."\n        )\n        self._set_target_state(\n            checkpoint_data.deployment_infos,\n            checkpoint_data.code_version,\n            checkpoint_data.config,\n            checkpoint_data.target_capacity,\n            checkpoint_data.target_capacity_direction,\n            checkpoint_data.deleting,\n        )\n\n    def _set_target_state(\n        self,\n        deployment_infos: Optional[Dict[str, DeploymentInfo]],\n        code_version: str,\n        target_config: Optional[ServeApplicationSchema],\n        target_capacity: Optional[float] = None,\n        target_capacity_direction: Optional[TargetCapacityDirection] = None,\n        deleting: bool = False,\n    ):\n        """Set application target state.\n\n        While waiting for build task to finish, this should be\n            (None, False)\n        When build task has finished and during normal operation, this should be\n            (target_deployments, False)\n        When a request to delete the application has been received, this should be\n            ({}, True)\n        """\n\n        if deleting:\n            self._update_status(ApplicationStatus.DELETING)\n        else:\n            self._update_status(ApplicationStatus.DEPLOYING)\n\n        if deployment_infos is None:\n            self._ingress_deployment_name = None\n        else:\n            for name, info in deployment_infos.items():\n                if info.ingress:\n                    self._ingress_deployment_name = name\n\n        target_state = ApplicationTargetState(\n            deployment_infos,\n            code_version,\n            target_config,\n            target_capacity,\n            target_capacity_direction,\n            deleting,\n        )\n\n        # Checkpoint ahead, so that if the controller crashes before we\n        # write to the target state, the target state will be recovered\n        # after the controller recovers\n        self._save_checkpoint_func(writeahead_checkpoints={self._name: target_state})\n        # Set target state\n        self._target_state = target_state\n\n    def _set_target_state_deleting(self):\n        """Set target state to deleting.\n\n        Wipes the target deployment infos, code version, and config.\n        """\n        self._set_target_state(dict(), None, None, None, None, True)\n\n    def _clear_target_state_and_store_config(\n        self, target_config: Optional[ServeApplicationSchema]\n    ):\n        """Clears the target state and stores the config."""\n\n        self._set_target_state(None, None, target_config, None, None, False)\n\n    def _delete_deployment(self, name):\n        id = DeploymentID(name=name, app_name=self._name)\n        self._endpoint_state.delete_endpoint(id)\n        self._deployment_state_manager.delete_deployment(id)\n\n    def delete(self):\n        """Delete the application"""\n        if self._status != ApplicationStatus.DELETING:\n            logger.info(\n                f"Deleting application \'{self._name}\'",\n                extra={"log_to_stderr": False},\n            )\n        self._set_target_state_deleting()\n\n    def is_deleted(self) -> bool:\n        """Check whether the application is already deleted.\n\n        For an application to be considered deleted, the target state has to be set to\n        deleting and all deployments have to be deleted.\n        """\n        return self._target_state.deleting and len(self._get_live_deployments()) == 0\n\n    def apply_deployment_info(\n        self,\n        deployment_name: str,\n        deployment_info: DeploymentInfo,\n    ) -> None:\n        """Deploys a deployment in the application."""\n        route_prefix = deployment_info.route_prefix\n        if route_prefix is not None and not route_prefix.startswith("/"):\n            raise RayServeException(\n                f\'Invalid route prefix "{route_prefix}", it must start with "/"\'\n            )\n\n        deployment_id = DeploymentID(name=deployment_name, app_name=self._name)\n\n        self._deployment_state_manager.deploy(deployment_id, deployment_info)\n\n        if deployment_info.route_prefix is not None:\n            config = deployment_info.deployment_config\n            self._endpoint_state.update_endpoint(\n                deployment_id,\n                # The current meaning of the "is_cross_language" field is ambiguous.\n                # We will work on optimizing and removing this field in the future.\n                # Instead of using the "is_cross_language" field, we will directly\n                # compare if the replica is Python, which will assist the Python\n                # router in determining if the replica invocation is a cross-language\n                # operation.\n                EndpointInfo(\n                    route=deployment_info.route_prefix,\n                    app_is_cross_language=config.deployment_language\n                    != DeploymentLanguage.PYTHON,\n                ),\n            )\n        else:\n            self._endpoint_state.delete_endpoint(deployment_id)\n\n    def deploy(self, deployment_infos: Dict[str, DeploymentInfo]):\n        """Deploy application from list of deployment infos.\n\n        This function should only be called if the app is being deployed\n        through serve.run instead of from a config.\n\n        Raises: RayServeException if there is more than one route prefix\n            or docs path.\n        """\n\n        # Check routes are unique in deployment infos\n        self._route_prefix, self._docs_path = self._check_routes(deployment_infos)\n\n        self._set_target_state(\n            deployment_infos=deployment_infos,\n            code_version=None,\n            target_config=None,\n            target_capacity=None,\n            target_capacity_direction=None,\n        )\n\n    def deploy_config(\n        self,\n        config: ServeApplicationSchema,\n        target_capacity: Optional[float],\n        target_capacity_direction: Optional[TargetCapacityDirection],\n        deployment_time: int,\n    ) -> None:\n        """Deploys an application config.\n\n        If the code version matches that of the current live deployments\n        then it only applies the updated config to the deployment state\n        manager. If the code version doesn\'t match, this will re-build\n        the application.\n        """\n\n        self._deployment_timestamp = deployment_time\n\n        config_version = get_app_code_version(config)\n        if config_version == self._target_state.code_version:\n            try:\n                overrided_infos = override_deployment_info(\n                    self._name,\n                    self._target_state.deployment_infos,\n                    config,\n                )\n                self._check_routes(overrided_infos)\n                self._set_target_state(\n                    # Code version doesn\'t change.\n                    code_version=self._target_state.code_version,\n                    # Everything else must reflect the new config.\n                    deployment_infos=overrided_infos,\n                    target_config=config,\n                    target_capacity=target_capacity,\n                    target_capacity_direction=target_capacity_direction,\n                )\n            except (TypeError, ValueError, RayServeException):\n                self._clear_target_state_and_store_config(config)\n                self._update_status(\n                    ApplicationStatus.DEPLOY_FAILED, traceback.format_exc()\n                )\n            except Exception:\n                self._clear_target_state_and_store_config(config)\n                self._update_status(\n                    ApplicationStatus.DEPLOY_FAILED,\n                    (\n                        f"Unexpected error occured while applying config for "\n                        f"application \'{self._name}\': \\n{traceback.format_exc()}"\n                    ),\n                )\n        else:\n            # If there is an in progress build task, cancel it.\n            if self._build_app_task_info and not self._build_app_task_info.finished:\n                logger.info(\n                    f"Received new config for application \'{self._name}\'. "\n                    "Cancelling previous request."\n                )\n                ray.cancel(self._build_app_task_info.obj_ref)\n\n            # Halt reconciliation of target deployments. A new target state\n            # will be set once the new app has finished building.\n            self._clear_target_state_and_store_config(config)\n\n            # Record telemetry for container runtime env feature\n            if self._target_state.config.runtime_env.get("container"):\n                ServeUsageTag.APP_CONTAINER_RUNTIME_ENV_USED.record("1")\n\n            # Kick off new build app task\n            logger.info(f"Building application \'{self._name}\'.")\n            build_app_obj_ref = build_serve_application.options(\n                runtime_env=config.runtime_env,\n                enable_task_events=RAY_SERVE_ENABLE_TASK_EVENTS,\n            ).remote(\n                config.import_path,\n                config.deployment_names,\n                config_version,\n                config.name,\n                config.args,\n            )\n            self._build_app_task_info = BuildAppTaskInfo(\n                obj_ref=build_app_obj_ref,\n                code_version=config_version,\n                config=config,\n                target_capacity=target_capacity,\n                target_capacity_direction=target_capacity_direction,\n                finished=False,\n            )\n\n    def _get_live_deployments(self) -> List[str]:\n        return self._deployment_state_manager.get_deployments_in_application(self._name)\n\n    def _determine_app_status(self) -> Tuple[ApplicationStatus, str]:\n        """Check deployment statuses and target state, and determine the\n        corresponding application status.\n\n        Returns:\n            Status (ApplicationStatus):\n                RUNNING: all deployments are healthy or autoscaling.\n                DEPLOYING: there is one or more updating deployments,\n                    and there are no unhealthy deployments.\n                DEPLOY_FAILED: one or more deployments became unhealthy\n                    while the application was deploying.\n                UNHEALTHY: one or more deployments became unhealthy\n                    while the application was running.\n                DELETING: the application is being deleted.\n            Error message (str):\n                Non-empty string if status is DEPLOY_FAILED or UNHEALTHY\n        """\n\n        if self._target_state.deleting:\n            return ApplicationStatus.DELETING, ""\n\n        # Get the lowest rank, i.e. highest priority, deployment status info object\n        # The deployment status info with highest priority determines the corresponding\n        # application status to set.\n        lowest_rank_status = min(\n            self.get_deployments_statuses(), key=lambda info: info.rank\n        )\n        if lowest_rank_status.status == DeploymentStatus.UNHEALTHY:\n            unhealthy_deployment_names = [\n                s.name\n                for s in self.get_deployments_statuses()\n                if s.status == DeploymentStatus.UNHEALTHY\n            ]\n            status_msg = f"The deployments {unhealthy_deployment_names} are UNHEALTHY."\n            if self._status in [\n                ApplicationStatus.DEPLOYING,\n                ApplicationStatus.DEPLOY_FAILED,\n            ]:\n                return ApplicationStatus.DEPLOY_FAILED, status_msg\n            else:\n                return ApplicationStatus.UNHEALTHY, status_msg\n        elif lowest_rank_status.status == DeploymentStatus.UPDATING:\n            return ApplicationStatus.DEPLOYING, ""\n        elif (\n            lowest_rank_status.status\n            in [DeploymentStatus.UPSCALING, DeploymentStatus.DOWNSCALING]\n            and lowest_rank_status.status_trigger\n            == DeploymentStatusTrigger.CONFIG_UPDATE_STARTED\n        ):\n            return ApplicationStatus.DEPLOYING, ""\n        else:\n            return ApplicationStatus.RUNNING, ""\n\n    def _reconcile_build_app_task(self) -> Tuple[Tuple, BuildAppStatus, str]:\n        """If necessary, reconcile the in-progress build task.\n\n        Returns:\n            Deploy arguments (Dict[str, DeploymentInfo]):\n                The deploy arguments returned from the build app task\n                and their code version.\n            Status (BuildAppStatus):\n                NO_TASK_IN_PROGRESS: There is no build task to reconcile.\n                SUCCEEDED: Task finished successfully.\n                FAILED: An error occurred during execution of build app task\n                IN_PROGRESS: Task hasn\'t finished yet.\n            Error message (str):\n                Non-empty string if status is DEPLOY_FAILED or UNHEALTHY\n        """\n        if self._build_app_task_info is None or self._build_app_task_info.finished:\n            return None, BuildAppStatus.NO_TASK_IN_PROGRESS, ""\n\n        if not check_obj_ref_ready_nowait(self._build_app_task_info.obj_ref):\n            return None, BuildAppStatus.IN_PROGRESS, ""\n\n        # Retrieve build app task result\n        self._build_app_task_info.finished = True\n        try:\n            args, err = ray.get(self._build_app_task_info.obj_ref)\n            if err is None:\n                logger.info(f"Built application \'{self._name}\' successfully.")\n            else:\n                return (\n                    None,\n                    BuildAppStatus.FAILED,\n                    f"Deploying app \'{self._name}\' failed with exception:\\n{err}",\n                )\n        except RuntimeEnvSetupError:\n            error_msg = (\n                f"Runtime env setup for app \'{self._name}\' failed:\\n"\n                + traceback.format_exc()\n            )\n            return None, BuildAppStatus.FAILED, error_msg\n        except Exception:\n            error_msg = (\n                f"Unexpected error occured while deploying application "\n                f"\'{self._name}\': \\n{traceback.format_exc()}"\n            )\n            return None, BuildAppStatus.FAILED, error_msg\n\n        # Convert serialized deployment args (returned by build app task)\n        # to deployment infos and apply option overrides from config\n        try:\n            deployment_infos = {\n                params["deployment_name"]: deploy_args_to_deployment_info(\n                    **params, app_name=self._name\n                )\n                for params in args\n            }\n            overrided_infos = override_deployment_info(\n                self._name, deployment_infos, self._build_app_task_info.config\n            )\n            self._route_prefix, self._docs_path = self._check_routes(overrided_infos)\n            return overrided_infos, BuildAppStatus.SUCCEEDED, ""\n        except (TypeError, ValueError, RayServeException):\n            return None, BuildAppStatus.FAILED, traceback.format_exc()\n        except Exception:\n            error_msg = (\n                f"Unexpected error occured while applying config for application "\n                f"\'{self._name}\': \\n{traceback.format_exc()}"\n            )\n            return None, BuildAppStatus.FAILED, error_msg\n\n    def _check_routes(\n        self, deployment_infos: Dict[str, DeploymentInfo]\n    ) -> Tuple[str, str]:\n        """Check route prefixes and docs paths of deployments in app.\n\n        There should only be one non-null route prefix. If there is one,\n        set it as the application route prefix. This function must be\n        run every control loop iteration because the target config could\n        be updated without kicking off a new task.\n\n        Returns: tuple of route prefix, docs path.\n        Raises: RayServeException if more than one route prefix or docs\n            path is found among deployments.\n        """\n        num_route_prefixes = 0\n        num_docs_paths = 0\n        route_prefix = None\n        docs_path = None\n        for info in deployment_infos.values():\n            # Update route prefix of application, which may be updated\n            # through a redeployed config.\n            if info.route_prefix is not None:\n                route_prefix = info.route_prefix\n                num_route_prefixes += 1\n            if info.docs_path is not None:\n                docs_path = info.docs_path\n                num_docs_paths += 1\n\n        if num_route_prefixes > 1:\n            raise RayServeException(\n                f\'Found multiple route prefixes from application "{self._name}",\'\n                " Please specify only one route prefix for the application "\n                "to avoid this issue."\n            )\n        # NOTE(zcin) This will not catch multiple FastAPI deployments in the application\n        # if user sets the docs path to None in their FastAPI app.\n        if num_docs_paths > 1:\n            raise RayServeException(\n                f\'Found multiple deployments in application "{self._name}" that have \'\n                "a docs path. This may be due to using multiple FastAPI deployments "\n                "in your application. Please only include one deployment with a docs "\n                "path in your application to avoid this issue."\n            )\n\n        return route_prefix, docs_path\n\n    def _reconcile_target_deployments(self) -> None:\n        """Reconcile target deployments in application target state.\n\n        Ensure each deployment is running on up-to-date info, and\n        remove outdated deployments from the application.\n        """\n\n        # Set target state for each deployment\n        for deployment_name, info in self._target_state.deployment_infos.items():\n            deploy_info = deepcopy(info)\n\n            # Apply the target capacity information to the deployment info.\n            deploy_info.set_target_capacity(\n                new_target_capacity=self._target_state.target_capacity,\n                new_target_capacity_direction=(\n                    self._target_state.target_capacity_direction\n                ),\n            )\n\n            # Apply the application logging config to the deployment logging config\n            # if it is not set.\n            if (\n                self._target_state.config\n                and self._target_state.config.logging_config\n                and deploy_info.deployment_config.logging_config is None\n            ):\n                deploy_info.deployment_config.logging_config = (\n                    self._target_state.config.logging_config\n                )\n            self.apply_deployment_info(deployment_name, deploy_info)\n\n        # Delete outdated deployments\n        for deployment_name in self._get_live_deployments():\n            if deployment_name not in self.target_deployments:\n                self._delete_deployment(deployment_name)\n\n    def update(self) -> bool:\n        """Attempts to reconcile this application to match its target state.\n\n        Updates the application status and status message based on the\n        current state of the system.\n\n        Returns:\n            A boolean indicating whether the application is ready to be\n            deleted.\n        """\n\n        infos, task_status, msg = self._reconcile_build_app_task()\n        if task_status == BuildAppStatus.SUCCEEDED:\n            self._set_target_state(\n                deployment_infos=infos,\n                code_version=self._build_app_task_info.code_version,\n                target_config=self._build_app_task_info.config,\n                target_capacity=self._build_app_task_info.target_capacity,\n                target_capacity_direction=(\n                    self._build_app_task_info.target_capacity_direction\n                ),\n            )\n        elif task_status == BuildAppStatus.FAILED:\n            self._update_status(ApplicationStatus.DEPLOY_FAILED, msg)\n\n        # Only reconcile deployments when the build app task is finished. If\n        # it\'s not finished, we don\'t know what the target list of deployments\n        # is, so we don\'t perform any reconciliation.\n        if self._target_state.deployment_infos is not None:\n            self._reconcile_target_deployments()\n            status, status_msg = self._determine_app_status()\n            self._update_status(status, status_msg)\n\n        # Check if app is ready to be deleted\n        if self._target_state.deleting:\n            return self.is_deleted()\n        return False\n\n    def get_checkpoint_data(self) -> ApplicationTargetState:\n        return self._target_state\n\n    def get_deployments_statuses(self) -> List[DeploymentStatusInfo]:\n        """Return all deployment status information"""\n        deployments = [\n            DeploymentID(name=deployment, app_name=self._name)\n            for deployment in self.target_deployments\n        ]\n        return self._deployment_state_manager.get_deployment_statuses(deployments)\n\n    def get_application_status_info(self) -> ApplicationStatusInfo:\n        """Return the application status information"""\n        return ApplicationStatusInfo(\n            self._status,\n            message=self._status_msg,\n            deployment_timestamp=self._deployment_timestamp,\n        )\n\n    def list_deployment_details(self) -> Dict[str, DeploymentDetails]:\n        """Gets detailed info on all live deployments in this application.\n        (Does not include deleted deployments.)\n\n        Returns:\n            A dictionary of deployment infos. The set of deployment info returned\n            may not be the full list of deployments that are part of the application.\n            This can happen when the application is still deploying and bringing up\n            deployments, or when the application is deleting and some deployments have\n            been deleted.\n        """\n        details = {\n            deployment_name: self._deployment_state_manager.get_deployment_details(\n                DeploymentID(name=deployment_name, app_name=self._name)\n            )\n            for deployment_name in self.target_deployments\n        }\n        return {k: v for k, v in details.items() if v is not None}\n\n    def _update_status(self, status: ApplicationStatus, status_msg: str = "") -> None:\n        if (\n            status_msg\n            and status\n            in [\n                ApplicationStatus.DEPLOY_FAILED,\n                ApplicationStatus.UNHEALTHY,\n            ]\n            and status_msg != self._status_msg\n        ):\n            logger.warning(status_msg)\n\n        self._status = status\n        self._status_msg = status_msg\n\n\nclass ApplicationStateManager:\n    def __init__(\n        self,\n        deployment_state_manager: DeploymentStateManager,\n        endpoint_state: EndpointState,\n        kv_store: KVStoreBase,\n    ):\n        self._deployment_state_manager = deployment_state_manager\n        self._endpoint_state = endpoint_state\n        self._kv_store = kv_store\n        self._application_states: Dict[str, ApplicationState] = dict()\n        self._recover_from_checkpoint()\n\n    def _recover_from_checkpoint(self):\n        checkpoint = self._kv_store.get(CHECKPOINT_KEY)\n        if checkpoint is not None:\n            application_state_info = cloudpickle.loads(checkpoint)\n\n            for app_name, checkpoint_data in application_state_info.items():\n                app_state = ApplicationState(\n                    app_name,\n                    self._deployment_state_manager,\n                    self._endpoint_state,\n                    self._save_checkpoint_func,\n                )\n                app_state.recover_target_state_from_checkpoint(checkpoint_data)\n                self._application_states[app_name] = app_state\n\n    def delete_application(self, name: str) -> None:\n        """Delete application by name"""\n        if name not in self._application_states:\n            return\n        self._application_states[name].delete()\n\n    def apply_deployment_args(self, name: str, deployment_args: List[Dict]) -> None:\n        """Apply list of deployment arguments to application target state.\n\n        This function should only be called if the app is being deployed\n        through serve.run instead of from a config.\n\n        Args:\n            name: application name\n            deployment_args_list: arguments for deploying a list of deployments.\n\n        Raises:\n            RayServeException: If the list of deployments is trying to\n                use a route prefix that is already used by another application\n        """\n\n        # Make sure route_prefix is not being used by other application.\n        live_route_prefixes: Dict[str, str] = {\n            self._application_states[app_name].route_prefix: app_name\n            for app_name, app_state in self._application_states.items()\n            if app_state.route_prefix is not None\n            and not app_state.status == ApplicationStatus.DELETING\n            and name != app_name\n        }\n\n        for deploy_param in deployment_args:\n            deploy_app_prefix = deploy_param.get("route_prefix")\n            if deploy_app_prefix in live_route_prefixes:\n                raise RayServeException(\n                    f"Prefix {deploy_app_prefix} is being used by application "\n                    f\'"{live_route_prefixes[deploy_app_prefix]}".\'\n                    f\' Failed to deploy application "{name}".\'\n                )\n\n        if name not in self._application_states:\n            self._application_states[name] = ApplicationState(\n                name,\n                self._deployment_state_manager,\n                self._endpoint_state,\n                self._save_checkpoint_func,\n            )\n        ServeUsageTag.NUM_APPS.record(str(len(self._application_states)))\n\n        deployment_infos = {\n            params["deployment_name"]: deploy_args_to_deployment_info(\n                **params, app_name=name\n            )\n            for params in deployment_args\n        }\n        self._application_states[name].deploy(deployment_infos)\n\n    def deploy_config(\n        self,\n        name: str,\n        app_config: ServeApplicationSchema,\n        deployment_time: float = 0,\n        target_capacity: Optional[float] = None,\n        target_capacity_direction: Optional[TargetCapacityDirection] = None,\n    ) -> None:\n        """Deploy application from config."""\n\n        if name not in self._application_states:\n            self._application_states[name] = ApplicationState(\n                name,\n                self._deployment_state_manager,\n                endpoint_state=self._endpoint_state,\n                save_checkpoint_func=self._save_checkpoint_func,\n            )\n        ServeUsageTag.NUM_APPS.record(str(len(self._application_states)))\n        self._application_states[name].deploy_config(\n            app_config,\n            target_capacity,\n            target_capacity_direction,\n            deployment_time=deployment_time,\n        )\n\n    def get_deployments(self, app_name: str) -> List[str]:\n        """Return all deployment names by app name"""\n        if app_name not in self._application_states:\n            return []\n        return self._application_states[app_name].target_deployments\n\n    def get_deployments_statuses(self, app_name: str) -> List[DeploymentStatusInfo]:\n        """Return all deployment statuses by app name"""\n        if app_name not in self._application_states:\n            return []\n        return self._application_states[app_name].get_deployments_statuses()\n\n    def get_app_status(self, name: str) -> ApplicationStatus:\n        if name not in self._application_states:\n            return ApplicationStatus.NOT_STARTED\n\n        return self._application_states[name].status\n\n    def get_app_status_info(self, name: str) -> ApplicationStatusInfo:\n        if name not in self._application_states:\n            return ApplicationStatusInfo(\n                ApplicationStatus.NOT_STARTED,\n                message=f"Application {name} doesn\'t exist",\n                deployment_timestamp=0,\n            )\n        return self._application_states[name].get_application_status_info()\n\n    def get_docs_path(self, app_name: str) -> Optional[str]:\n        return self._application_states[app_name].docs_path\n\n    def get_route_prefix(self, name: str) -> Optional[str]:\n        return self._application_states[name].route_prefix\n\n    def get_ingress_deployment_name(self, name: str) -> Optional[str]:\n        if name not in self._application_states:\n            return None\n\n        return self._application_states[name].ingress_deployment\n\n    def list_app_statuses(self) -> Dict[str, ApplicationStatusInfo]:\n        """Return a dictionary with {app name: application info}"""\n        return {\n            name: self._application_states[name].get_application_status_info()\n            for name in self._application_states\n        }\n\n    def list_deployment_details(self, name: str) -> Dict[str, DeploymentDetails]:\n        """Gets detailed info on all deployments in specified application."""\n        if name not in self._application_states:\n            return {}\n        return self._application_states[name].list_deployment_details()\n\n    def update(self):\n        """Update each application state"""\n        apps_to_be_deleted = []\n        for name, app in self._application_states.items():\n            ready_to_be_deleted = app.update()\n            if ready_to_be_deleted:\n                apps_to_be_deleted.append(name)\n                logger.debug(f"Application \'{name}\' deleted successfully.")\n\n        if len(apps_to_be_deleted) > 0:\n            for app_name in apps_to_be_deleted:\n                del self._application_states[app_name]\n            ServeUsageTag.NUM_APPS.record(str(len(self._application_states)))\n\n    def shutdown(self) -> None:\n        for app_state in self._application_states.values():\n            app_state.delete()\n\n        self._kv_store.delete(CHECKPOINT_KEY)\n\n    def is_ready_for_shutdown(self) -> bool:\n        """Return whether all applications have shut down.\n\n        Iterate through all application states and check if all their applications\n        are deleted.\n        """\n        return all(\n            app_state.is_deleted() for app_state in self._application_states.values()\n        )\n\n    def _save_checkpoint_func(\n        self, *, writeahead_checkpoints: Optional[Dict[str, ApplicationTargetState]]\n    ) -> None:\n        """Write a checkpoint of all application states."""\n\n        application_state_info = {\n            app_name: app_state.get_checkpoint_data()\n            for app_name, app_state in self._application_states.items()\n        }\n\n        if writeahead_checkpoints is not None:\n            application_state_info.update(writeahead_checkpoints)\n\n        self._kv_store.put(\n            CHECKPOINT_KEY,\n            cloudpickle.dumps(application_state_info),\n        )\n\n\n@ray.remote(num_cpus=0, max_calls=1)\ndef build_serve_application(\n    import_path: str,\n    config_deployments: List[str],\n    code_version: str,\n    name: str,\n    args: Dict,\n) -> Tuple[List[Dict], Optional[str]]:\n    """Import and build a Serve application.\n\n    Args:\n        import_path: import path to top-level bound deployment.\n        config_deployments: list of deployment names specified in config\n            with deployment override options. This is used to check that\n            all deployments specified in the config are valid.\n        code_version: code version inferred from app config. All\n            deployment versions are set to this code version.\n        name: application name. If specified, application will be deployed\n            without removing existing applications.\n        args: Arguments to be passed to the application builder.\n        logging_config: The application logging config, if deployment logging\n            config is not set, application logging config will be applied to the\n            deployment logging config.\n    Returns:\n        Deploy arguments: a list of deployment arguments if application\n            was built successfully, otherwise None.\n        Error message: a string if an error was raised, otherwise None.\n    """\n    try:\n        from ray.serve._private.api import call_app_builder_with_args_if_necessary\n        from ray.serve._private.deployment_graph_build import build as pipeline_build\n        from ray.serve._private.deployment_graph_build import (\n            get_and_validate_ingress_deployment,\n        )\n\n        # Import and build the application.\n        app = call_app_builder_with_args_if_necessary(import_attr(import_path), args)\n        deployments = pipeline_build(app._get_internal_dag_node(), name)\n        ingress = get_and_validate_ingress_deployment(deployments)\n\n        deploy_args_list = []\n        for deployment in deployments:\n            is_ingress = deployment.name == ingress.name\n            deploy_args_list.append(\n                get_deploy_args(\n                    name=deployment._name,\n                    replica_config=deployment._replica_config,\n                    ingress=is_ingress,\n                    deployment_config=deployment._deployment_config,\n                    version=code_version,\n                    route_prefix=deployment.route_prefix,\n                    docs_path=deployment._docs_path,\n                )\n            )\n        return deploy_args_list, None\n    except KeyboardInterrupt:\n        # Error is raised when this task is canceled with ray.cancel(), which\n        # happens when deploy_apps() is called.\n        logger.info("Existing config deployment request terminated.")\n        return None, None\n    except Exception:\n        return None, traceback.format_exc()\n\n\ndef override_deployment_info(\n    app_name: str,\n    deployment_infos: Dict[str, DeploymentInfo],\n    override_config: Optional[ServeApplicationSchema],\n) -> Dict[str, DeploymentInfo]:\n    """Override deployment infos with options from app config.\n\n    Args:\n        app_name: application name\n        deployment_infos: deployment info loaded from code\n        override_config: application config deployed by user with\n            options to override those loaded from code.\n\n    Returns: the updated deployment infos.\n\n    Raises:\n        ValueError: If config options have invalid values.\n        TypeError: If config options have invalid types.\n    """\n\n    deployment_infos = deepcopy(deployment_infos)\n    if override_config is None:\n        return deployment_infos\n\n    config_dict = override_config.dict(exclude_unset=True)\n    deployment_override_options = config_dict.get("deployments", [])\n\n    # Override options for each deployment listed in the config.\n    for options in deployment_override_options:\n        if "max_concurrent_queries" in options or "max_ongoing_requests" in options:\n            options["max_ongoing_requests"] = options.get(\n                "max_ongoing_requests"\n            ) or options.get("max_concurrent_queries")\n\n        deployment_name = options["name"]\n        info = deployment_infos[deployment_name]\n        original_options = info.deployment_config.dict()\n        original_options["user_configured_option_names"].update(set(options))\n\n        # Override `max_ongoing_requests` and `autoscaling_config` if\n        # `num_replicas="auto"`\n        if options.get("num_replicas") == "auto":\n            options["num_replicas"] = None\n            if (\n                "max_ongoing_requests"\n                not in original_options["user_configured_option_names"]\n            ):\n                options["max_ongoing_requests"] = NEW_DEFAULT_MAX_ONGOING_REQUESTS\n\n            # If `autoscaling_config` is specified, its values override\n            # the default `num_replicas="auto"` configuration\n            autoscaling_config = (\n                options.get("autoscaling_config")\n                or info.deployment_config.autoscaling_config\n            )\n            if autoscaling_config:\n                new_config = AutoscalingConfig.default().dict()\n                new_config.update(autoscaling_config)\n                options["autoscaling_config"] = AutoscalingConfig(**new_config)\n\n        # What to pass to info.update\n        override_options = dict()\n\n        # Override route prefix if specified in deployment config\n        deployment_route_prefix = options.pop("route_prefix", DEFAULT.VALUE)\n        if deployment_route_prefix is not DEFAULT.VALUE:\n            override_options["route_prefix"] = deployment_route_prefix\n\n        # Merge app-level and deployment-level runtime_envs.\n        replica_config = info.replica_config\n        app_runtime_env = override_config.runtime_env\n        if "ray_actor_options" in options:\n            # If specified, get ray_actor_options from config\n            override_actor_options = options.pop("ray_actor_options", {})\n        else:\n            # Otherwise, get options from application code (and default to {}\n            # if the code sets options to None).\n            override_actor_options = replica_config.ray_actor_options or {}\n\n        override_placement_group_bundles = options.pop(\n            "placement_group_bundles", replica_config.placement_group_bundles\n        )\n        override_placement_group_strategy = options.pop(\n            "placement_group_strategy", replica_config.placement_group_strategy\n        )\n\n        override_max_replicas_per_node = options.pop(\n            "max_replicas_per_node", replica_config.max_replicas_per_node\n        )\n\n        # Record telemetry for container runtime env feature at deployment level\n        if override_actor_options.get("runtime_env") and override_actor_options[\n            "runtime_env"\n        ].get("container"):\n            ServeUsageTag.DEPLOYMENT_CONTAINER_RUNTIME_ENV_USED.record("1")\n\n        merged_env = override_runtime_envs_except_env_vars(\n            app_runtime_env, override_actor_options.get("runtime_env", {})\n        )\n        override_actor_options.update({"runtime_env": merged_env})\n\n        replica_config.update(\n            ray_actor_options=override_actor_options,\n            placement_group_bundles=override_placement_group_bundles,\n            placement_group_strategy=override_placement_group_strategy,\n            max_replicas_per_node=override_max_replicas_per_node,\n        )\n        override_options["replica_config"] = replica_config\n\n        # Override deployment config options\n        options.pop("name", None)\n        original_options.update(options)\n        override_options["deployment_config"] = DeploymentConfig(**original_options)\n        deployment_infos[deployment_name] = info.update(**override_options)\n\n        deployment_config = deployment_infos[deployment_name].deployment_config\n        if (\n            deployment_config.autoscaling_config is not None\n            and deployment_config.max_ongoing_requests\n            < deployment_config.autoscaling_config.get_target_ongoing_requests()\n        ):\n            logger.warning(\n                "Autoscaling will never happen, "\n                "because \'max_ongoing_requests\' is less than "\n                "\'target_ongoing_requests\' now."\n            )\n\n    # Overwrite ingress route prefix\n    app_route_prefix = config_dict.get("route_prefix", DEFAULT.VALUE)\n    for deployment in list(deployment_infos.values()):\n        if (\n            app_route_prefix is not DEFAULT.VALUE\n            and deployment.route_prefix is not None\n        ):\n            deployment.route_prefix = app_route_prefix\n\n    return deployment_infos\n',
            'python/ray/serve/tests/test_deploy_2.py': 'import functools\nimport os\nimport sys\nimport threading\nimport time\nfrom concurrent.futures.thread import ThreadPoolExecutor\nfrom typing import Dict\n\nimport pytest\nimport requests\n\nimport ray\nfrom ray import serve\nfrom ray._private.pydantic_compat import ValidationError\nfrom ray._private.test_utils import SignalActor, wait_for_condition\nfrom ray.serve._private.common import ApplicationStatus, DeploymentStatus\nfrom ray.serve._private.logging_utils import (\n    get_component_log_file_name,\n    get_serve_logs_dir,\n)\nfrom ray.serve._private.test_utils import check_deployment_status, check_num_replicas_eq\nfrom ray.util.state import list_actors\n\n\n@pytest.mark.parametrize("prefixes", [[None, "/f", None], ["/f", None, "/f"]])\ndef test_deploy_nullify_route_prefix(serve_instance, prefixes):\n    # With multi dags support, dag driver will receive all route\n    # prefix when route_prefix is "None", since "None" will be converted\n    # to "/" internally.\n    # Note: the expose http endpoint will still be removed for internal\n    # dag node by setting "None" to route_prefix\n    @serve.deployment\n    def f(*args):\n        return "got me"\n\n    for prefix in prefixes:\n        dag = f.options(route_prefix=prefix).bind()\n        handle = serve.run(dag)\n        assert requests.get("http://localhost:8000/f").status_code == 200\n        assert requests.get("http://localhost:8000/f").text == "got me"\n        assert handle.remote().result() == "got me"\n\n\n@pytest.mark.timeout(10, method="thread")\ndef test_deploy_empty_bundle(serve_instance):\n    @serve.deployment(ray_actor_options={"num_cpus": 0})\n    class D:\n        def hello(self, _):\n            return "hello"\n\n    # This should succesfully terminate within the provided time-frame.\n    serve.run(D.bind())\n\n\ndef test_deployment_error_handling(serve_instance):\n    @serve.deployment\n    def f():\n        pass\n\n    with pytest.raises(\n        ValidationError, match="1 validation error for RayActorOptionsSchema.*"\n    ):\n        # This is an invalid configuration since dynamic upload of working\n        # directories is not supported. The error this causes in the controller\n        # code should be caught and reported back to the `deploy` caller.\n\n        serve.run(\n            f.options(ray_actor_options={"runtime_env": {"working_dir": "."}}).bind()\n        )\n\n\ndef test_json_serialization_user_config(serve_instance):\n    """See https://github.com/ray-project/ray/issues/25345.\n\n    See https://github.com/ray-project/ray/pull/26235 for additional context\n    about this test.\n    """\n\n    @serve.deployment(name="simple-deployment")\n    class SimpleDeployment:\n        value: str\n        nested_value: str\n\n        def reconfigure(self, config: Dict) -> None:\n            self.value = config["value"]\n            self.nested_value = config["nested"]["value"]\n\n        def get_value(self) -> None:\n            return self.value\n\n        def get_nested_value(self) -> None:\n            return self.nested_value\n\n    app = SimpleDeployment.options(\n        user_config={\n            "value": "Success!",\n            "nested": {"value": "Success!"},\n        }\n    ).bind()\n    handle = serve.run(app)\n\n    assert handle.get_value.remote().result() == "Success!"\n    assert handle.get_nested_value.remote().result() == "Success!"\n\n    handle = serve.run(\n        SimpleDeployment.options(\n            user_config={\n                "value": "Failure!",\n                "another-value": "Failure!",\n                "nested": {"value": "Success!"},\n            }\n        ).bind()\n    )\n\n    assert handle.get_value.remote().result() == "Failure!"\n    assert handle.get_nested_value.remote().result() == "Success!"\n\n\ndef test_http_proxy_request_cancellation(serve_instance):\n    # https://github.com/ray-project/ray/issues/21425\n    s = SignalActor.remote()\n\n    @serve.deployment(max_ongoing_requests=1)\n    class A:\n        def __init__(self) -> None:\n            self.counter = 0\n\n        async def __call__(self):\n            self.counter += 1\n            ret_val = self.counter\n            await s.wait.remote()\n            return ret_val\n\n    serve.run(A.bind())\n\n    url = "http://127.0.0.1:8000/A"\n    with ThreadPoolExecutor() as pool:\n        # Send the first request, it should block for the result\n        first_blocking_fut = pool.submit(\n            functools.partial(requests.get, url, timeout=100)\n        )\n        time.sleep(1)\n        assert not first_blocking_fut.done()\n\n        # Send more requests, these should be queued in handle.\n        # But because first request is hanging and these have low timeout.\n        # They should all disconnect from http connection.\n        # These requests should never reach the replica.\n        rest_blocking_futs = [\n            pool.submit(functools.partial(requests.get, url, timeout=0.5))\n            for _ in range(3)\n        ]\n        time.sleep(1)\n        assert all(f.done() for f in rest_blocking_futs)\n\n        # Now unblock the first request.\n        ray.get(s.send.remote())\n        assert first_blocking_fut.result().text == "1"\n\n    # Sending another request to verify that only one request has been\n    # processed so far.\n    assert requests.get(url).text == "2"\n\n\ndef test_nonserializable_deployment(serve_instance):\n    lock = threading.Lock()\n\n    class D:\n        def hello(self, _):\n            return lock\n\n    # Check that the `inspect_serializability` trace was printed\n    with pytest.raises(\n        TypeError,\n        match=r"Could not serialize the deployment[\\s\\S]*was found to be non-serializable.*",  # noqa\n    ):\n        serve.deployment(D)\n\n    @serve.deployment\n    class E:\n        def __init__(self, arg):\n            self.arg = arg\n\n    with pytest.raises(TypeError, match="pickle"):\n        serve.run(E.bind(lock))\n\n    with pytest.raises(TypeError, match="pickle"):\n        serve.run(E.bind(arg=lock))\n\n\ndef test_deploy_application_unhealthy(serve_instance):\n    """Test deploying an application that becomes unhealthy."""\n\n    @ray.remote\n    class Event:\n        def __init__(self):\n            self.is_set = False\n\n        def set(self):\n            self.is_set = True\n\n        def is_set(self):\n            return self.is_set\n\n    event = Event.remote()\n\n    @serve.deployment(health_check_period_s=1, health_check_timeout_s=3)\n    class Model:\n        def __call__(self):\n            return "hello world"\n\n        def check_health(self):\n            if ray.get(event.is_set.remote()):\n                raise RuntimeError("Intentionally failing.")\n\n    handle = serve.run(Model.bind(), name="app")\n    assert handle.remote().result() == "hello world"\n    assert serve.status().applications["app"].status == ApplicationStatus.RUNNING\n\n    # When a deployment becomes unhealthy, application should transition -> UNHEALTHY\n    event.set.remote()\n    wait_for_condition(\n        lambda: serve.status().applications["app"].status == ApplicationStatus.UNHEALTHY\n    )\n\n    # Check that application stays unhealthy\n    for _ in range(10):\n        assert serve.status().applications["app"].status == ApplicationStatus.UNHEALTHY\n        time.sleep(0.1)\n\n    # At least 10 control loop iterations should have passed. Check that\n    # the logs from application state manager notifying about unhealthy\n    # deployments doesn\'t spam, they should get printed only once.\n    controller_pid = [\n        actor["pid"]\n        for actor in list_actors()\n        if actor["name"] == "SERVE_CONTROLLER_ACTOR"\n    ][0]\n    controller_log_file_name = get_component_log_file_name(\n        "controller", controller_pid, component_type=None, suffix=".log"\n    )\n    controller_log_path = os.path.join(get_serve_logs_dir(), controller_log_file_name)\n    with open(controller_log_path, "r") as f:\n        s = f.read()\n        assert s.count("The deployments [\'Model\'] are UNHEALTHY.") <= 1\n\n\n@pytest.mark.skipif(\n    sys.platform == "win32", reason="Runtime env support experimental on windows"\n)\ndef test_deploy_bad_pip_package_deployment(serve_instance):\n    """Test deploying with a bad runtime env at deployment level."""\n\n    @serve.deployment(ray_actor_options={"runtime_env": {"pip": ["does_not_exist"]}})\n    class Model:\n        def __call__(self):\n            return "hello world"\n\n    serve._run(Model.bind(), _blocking=False)\n\n    def check_fail():\n        app_status = serve.status().applications["default"]\n        assert app_status.status == ApplicationStatus.DEPLOY_FAILED\n        deployment_message = app_status.deployments["Model"].message\n        assert "No matching distribution found for does_not_exist" in deployment_message\n        return True\n\n    wait_for_condition(check_fail, timeout=15)\n\n\ndef test_deploy_same_deployment_name_different_app(serve_instance):\n    @serve.deployment\n    class Model:\n        def __init__(self, name):\n            self.name = name\n\n        def __call__(self):\n            return f"hello {self.name}"\n\n    serve.run(Model.bind("alice"), name="app1", route_prefix="/app1")\n    serve.run(Model.bind("bob"), name="app2", route_prefix="/app2")\n\n    assert requests.get("http://localhost:8000/app1").text == "hello alice"\n    assert requests.get("http://localhost:8000/app2").text == "hello bob"\n    routes = requests.get("http://localhost:8000/-/routes").json()\n    assert routes["/app1"] == "app1"\n    assert routes["/app2"] == "app2"\n\n    app1_status = serve.status().applications["app1"]\n    app2_status = serve.status().applications["app2"]\n    assert app1_status.status == "RUNNING"\n    assert app1_status.deployments["Model"].status == "HEALTHY"\n    assert app2_status.status == "RUNNING"\n    assert app2_status.deployments["Model"].status == "HEALTHY"\n\n\n@pytest.mark.parametrize("use_options", [True, False])\ndef test_num_replicas_auto(serve_instance, use_options):\n    """Test `num_replicas="auto"`."""\n\n    signal = SignalActor.remote()\n\n    class A:\n        async def __call__(self):\n            await signal.wait.remote()\n\n    if use_options:\n        A = serve.deployment(A).options(\n            num_replicas="auto",\n            autoscaling_config={"metrics_interval_s": 1, "upscale_delay_s": 1},\n            graceful_shutdown_timeout_s=1,\n        )\n    else:\n        A = serve.deployment(\n            num_replicas="auto",\n            autoscaling_config={"metrics_interval_s": 1, "upscale_delay_s": 1},\n            graceful_shutdown_timeout_s=1,\n        )(A)\n\n    h = serve.run(A.bind(), name="default")\n    wait_for_condition(\n        check_deployment_status, name="A", expected_status=DeploymentStatus.HEALTHY\n    )\n    check_num_replicas_eq("A", 1)\n\n    app_details = serve_instance.get_serve_details()["applications"]["default"]\n    deployment_config = app_details["deployments"]["A"]["deployment_config"]\n    # Set by `num_replicas="auto"`\n    assert "num_replicas" not in deployment_config\n    assert deployment_config["max_ongoing_requests"] == 5\n    assert deployment_config["autoscaling_config"] == {\n        # Set by `num_replicas="auto"`\n        "target_ongoing_requests": 2.0,\n        "target_num_ongoing_requests_per_replica": 2.0,\n        "min_replicas": 1,\n        "max_replicas": 100,\n        # Overrided by `autoscaling_config`\n        "metrics_interval_s": 1.0,\n        "upscale_delay_s": 1.0,\n        # Untouched defaults\n        "look_back_period_s": 30.0,\n        "downscale_delay_s": 600.0,\n        "upscale_smoothing_factor": None,\n        "downscale_smoothing_factor": None,\n        "upscaling_factor": None,\n        "downscaling_factor": None,\n        "smoothing_factor": 1.0,\n        "initial_replicas": None,\n    }\n\n    for i in range(3):\n        [h.remote() for _ in range(2)]\n\n        def check_num_waiters(target: int):\n            assert ray.get(signal.cur_num_waiters.remote()) == target\n            return True\n\n        wait_for_condition(check_num_waiters, target=2 * (i + 1))\n        print(time.time(), f"Number of waiters on signal reached {2*(i+1)}.")\n        wait_for_condition(check_num_replicas_eq, name="A", target=i + 1)\n        print(time.time(), f"Confirmed number of replicas are at {i+1}.")\n\n\nif __name__ == "__main__":\n    sys.exit(pytest.main(["-v", "-s", __file__]))\n',
            'python/ray/serve/tests/test_deploy_app.py': 'import logging\nimport re\nimport subprocess\nimport sys\nimport time\nfrom contextlib import contextmanager\nfrom copy import copy\nfrom functools import partial\nfrom typing import Dict, List, Union\n\nimport pytest\nimport requests\n\nimport ray\nimport ray._private.state\nimport ray.actor\nfrom ray import serve\nfrom ray._private.test_utils import SignalActor, wait_for_condition\nfrom ray.serve._private.client import ServeControllerClient\nfrom ray.serve._private.common import (\n    ApplicationStatus,\n    DeploymentID,\n    DeploymentStatus,\n    ReplicaID,\n)\nfrom ray.serve._private.constants import SERVE_DEFAULT_APP_NAME, SERVE_NAMESPACE\nfrom ray.serve._private.test_utils import (\n    check_num_replicas_eq,\n    check_num_replicas_gte,\n    check_num_replicas_lte,\n)\nfrom ray.serve.context import _get_global_client\nfrom ray.serve.schema import ServeDeploySchema, ServeInstanceDetails\nfrom ray.serve.tests.common.remote_uris import (\n    TEST_DAG_PINNED_URI,\n    TEST_RUNTIME_ENV_PINNED_URI,\n)\nfrom ray.tests.conftest import call_ray_stop_only  # noqa: F401\nfrom ray.util.state import list_actors\n\n\n@pytest.fixture\ndef shutdown_ray_and_serve():\n    serve.shutdown()\n    if ray.is_initialized():\n        ray.shutdown()\n    yield\n    serve.shutdown()\n    if ray.is_initialized():\n        ray.shutdown()\n\n\n@contextmanager\ndef start_and_shutdown_ray_cli():\n    subprocess.check_output(["ray", "stop", "--force"])\n    wait_for_condition(_check_ray_stop, timeout=15)\n    subprocess.check_output(["ray", "start", "--head"])\n\n    yield\n\n    subprocess.check_output(["ray", "stop", "--force"])\n    wait_for_condition(_check_ray_stop, timeout=15)\n\n\n@pytest.fixture(scope="module")\ndef start_and_shutdown_ray_cli_module():\n    with start_and_shutdown_ray_cli():\n        yield\n\n\ndef _check_ray_stop():\n    try:\n        requests.get("http://localhost:52365/api/ray/version")\n        return False\n    except Exception:\n        return True\n\n\n@pytest.fixture(scope="function")\ndef client(start_and_shutdown_ray_cli_module, shutdown_ray_and_serve):\n    wait_for_condition(\n        lambda: requests.get("http://localhost:52365/api/ray/version").status_code\n        == 200,\n        timeout=15,\n    )\n    ray.init(address="auto", namespace=SERVE_NAMESPACE)\n    serve.start()\n    yield _get_global_client()\n\n\ndef check_running():\n    assert (\n        serve.status().applications[SERVE_DEFAULT_APP_NAME].status\n        == ApplicationStatus.RUNNING\n    )\n    return True\n\n\ndef check_endpoint(endpoint: str, json: Union[List, Dict], expected: str):\n    resp = requests.post(f"http://localhost:8000/{endpoint}", json=json)\n    assert resp.text == expected\n    return True\n\n\ndef check_deployments_dead(deployment_ids: List[DeploymentID]):\n    prefixes = [f"{id.app_name}#{id.name}" for id in deployment_ids]\n    actor_names = [\n        actor["name"] for actor in list_actors(filters=[("state", "=", "ALIVE")])\n    ]\n    return all(f"ServeReplica::{p}" not in actor_names for p in prefixes)\n\n\ndef get_test_config() -> Dict:\n    return {"import_path": "ray.serve.tests.test_config_files.pizza.serve_dag"}\n\n\ndef get_test_deploy_config() -> Dict:\n    return {\n        "applications": [\n            {\n                "name": "app1",\n                "route_prefix": "/app1",\n                "import_path": "ray.serve.tests.test_config_files.pizza.serve_dag",\n            },\n            {\n                "name": "app2",\n                "route_prefix": "/app2",\n                "import_path": "ray.serve.tests.test_config_files.pizza.serve_dag",\n                "deployments": [\n                    {\n                        "name": "Adder",\n                        "user_config": {\n                            "increment": 3,\n                        },\n                    },\n                    {\n                        "name": "Multiplier",\n                        "user_config": {\n                            "factor": 4,\n                        },\n                    },\n                ],\n            },\n        ],\n    }\n\n\ndef check_multi_app():\n    """\n    Checks the applications deployed through the config from\n    get_test_deploy_config().\n    """\n\n    wait_for_condition(\n        check_endpoint,\n        endpoint="app1",\n        json=["ADD", 2],\n        expected="4 pizzas please!",\n    )\n    wait_for_condition(\n        check_endpoint,\n        endpoint="app1",\n        json=["MUL", 3],\n        expected="9 pizzas please!",\n    )\n\n    wait_for_condition(\n        check_endpoint,\n        endpoint="app2",\n        json=["ADD", 2],\n        expected="5 pizzas please!",\n    )\n    wait_for_condition(\n        check_endpoint,\n        endpoint="app2",\n        json=["MUL", 3],\n        expected="12 pizzas please!",\n    )\n\n\ndef test_deploy_multi_app_basic(client: ServeControllerClient):\n    config = ServeDeploySchema.parse_obj(get_test_deploy_config())\n    client.deploy_apps(config)\n    check_multi_app()\n\n\ndef test_deploy_multi_app_update_config(client: ServeControllerClient):\n    config = get_test_deploy_config()\n    client.deploy_apps(ServeDeploySchema.parse_obj(config))\n    check_multi_app()\n\n    config["applications"][0]["deployments"] = [\n        {\n            "name": "Adder",\n            "user_config": {\n                "increment": -1,\n            },\n        },\n    ]\n\n    config["applications"][1]["deployments"] = [\n        {\n            "name": "Adder",\n            "user_config": {\n                "increment": 10,\n            },\n        },\n    ]\n\n    client.deploy_apps(ServeDeploySchema.parse_obj(config))\n    wait_for_condition(\n        lambda: requests.post("http://localhost:8000/app1", json=["ADD", 2]).text\n        == "1 pizzas please!"\n    )\n    wait_for_condition(\n        lambda: requests.post("http://localhost:8000/app2", json=["ADD", 2]).text\n        == "12 pizzas please!"\n    )\n\n\ndef test_deploy_multi_app_update_num_replicas(client: ServeControllerClient):\n    config = get_test_deploy_config()\n    client.deploy_apps(ServeDeploySchema.parse_obj(config))\n    check_multi_app()\n\n    actors = list_actors(filters=[("state", "=", "ALIVE")])\n\n    # app1\n    config["applications"][0]["deployments"] = [\n        {\n            "name": "Adder",\n            "num_replicas": 2,  # +1\n            "user_config": {\n                "increment": 0,\n            },\n            "ray_actor_options": {"num_cpus": 0.1},\n        },\n        {\n            "name": "Multiplier",\n            "num_replicas": 3,  # +2\n            "user_config": {\n                "factor": 0,\n            },\n            "ray_actor_options": {"num_cpus": 0.1},\n        },\n    ]\n\n    # app2\n    config["applications"][1]["deployments"] = [\n        {\n            "name": "Adder",\n            "num_replicas": 3,  # +2\n            "user_config": {\n                "increment": 100,\n            },\n            "ray_actor_options": {"num_cpus": 0.1},\n        },\n        {\n            "name": "Multiplier",\n            "num_replicas": 4,  # +3\n            "user_config": {\n                "factor": 0,\n            },\n            "ray_actor_options": {"num_cpus": 0.1},\n        },\n    ]\n\n    client.deploy_apps(ServeDeploySchema.parse_obj(config))\n    wait_for_condition(\n        lambda: requests.post("http://localhost:8000/app1", json=["ADD", 2]).text\n        == "2 pizzas please!"\n    )\n    wait_for_condition(\n        lambda: requests.post("http://localhost:8000/app2", json=["ADD", 2]).text\n        == "102 pizzas please!"\n    )\n\n    wait_for_condition(\n        lambda: serve.status().applications["app1"].status == ApplicationStatus.RUNNING,\n        timeout=15,\n    )\n    wait_for_condition(\n        lambda: serve.status().applications["app2"].status == ApplicationStatus.RUNNING,\n        timeout=15,\n    )\n\n    updated_actors = list_actors(filters=[("state", "=", "ALIVE")])\n    assert len(updated_actors) == len(actors) + 8\n\n\ndef test_deploy_multi_app_update_timestamp(client: ServeControllerClient):\n    assert "app1" not in serve.status().applications\n    assert "app2" not in serve.status().applications\n\n    config = get_test_deploy_config()\n    client.deploy_apps(ServeDeploySchema.parse_obj(config))\n\n    first_deploy_time_app1 = serve.status().applications["app1"].last_deployed_time_s\n    first_deploy_time_app2 = serve.status().applications["app2"].last_deployed_time_s\n\n    assert first_deploy_time_app1 > 0 and first_deploy_time_app2 > 0\n    time.sleep(0.1)\n\n    # app1\n    config["applications"][0]["deployments"] = [\n        {\n            "name": "Adder",\n            "num_replicas": 2,\n        },\n    ]\n    # app2\n    config["applications"][1]["deployments"] = [\n        {\n            "name": "Adder",\n            "num_replicas": 3,\n        },\n    ]\n    client.deploy_apps(ServeDeploySchema.parse_obj(config))\n\n    assert (\n        serve.status().applications["app1"].last_deployed_time_s\n        > first_deploy_time_app1\n        and serve.status().applications["app2"].last_deployed_time_s\n        > first_deploy_time_app2\n    )\n    assert {\n        serve.status().applications["app1"].status,\n        serve.status().applications["app1"].status,\n    } <= {\n        ApplicationStatus.DEPLOYING,\n        ApplicationStatus.RUNNING,\n    }\n    wait_for_condition(\n        lambda: requests.post("http://localhost:8000/app1", json=["ADD", 2]).text\n        == "4 pizzas please!"\n    )\n\n\ndef test_deploy_multi_app_overwrite_apps(client: ServeControllerClient):\n    """Check that redeploying different apps with same names works as expected."""\n\n    world_import_path = "ray.serve.tests.test_config_files.world.DagNode"\n    pizza_import_path = "ray.serve.tests.test_config_files.pizza.serve_dag"\n    test_config = ServeDeploySchema.parse_obj(\n        {\n            "applications": [\n                {\n                    "name": "app1",\n                    "route_prefix": "/app1",\n                    "import_path": world_import_path,\n                },\n                {\n                    "name": "app2",\n                    "route_prefix": "/app2",\n                    "import_path": pizza_import_path,\n                },\n            ],\n        }\n    )\n    client.deploy_apps(test_config)\n\n    wait_for_condition(\n        lambda: requests.get("http://localhost:8000/app1").text == "wonderful world"\n    )\n    wait_for_condition(\n        lambda: requests.post("http://localhost:8000/app2", json=["ADD", 2]).text\n        == "4 pizzas please!"\n    )\n\n    # Switch the two application import paths\n    test_config.applications[0].import_path = pizza_import_path\n    test_config.applications[1].import_path = world_import_path\n    client.deploy_apps(test_config)\n\n    wait_for_condition(\n        lambda: requests.post("http://localhost:8000/app1", json=["ADD", 2]).text\n        == "4 pizzas please!"\n    )\n    wait_for_condition(\n        lambda: requests.get("http://localhost:8000/app2").text == "wonderful world"\n    )\n\n\ndef test_deploy_multi_app_overwrite_apps2(client: ServeControllerClient):\n    """Check that deploying a new set of applications removes old ones."""\n\n    world_import_path = "ray.serve.tests.test_config_files.world.DagNode"\n    pizza_import_path = "ray.serve.tests.test_config_files.pizza.serve_dag"\n    test_config = ServeDeploySchema.parse_obj(\n        {\n            "applications": [\n                {\n                    "name": "app1",\n                    "route_prefix": "/app1",\n                    "import_path": world_import_path,\n                },\n                {\n                    "name": "app2",\n                    "route_prefix": "/app2",\n                    "import_path": pizza_import_path,\n                },\n            ],\n        }\n    )\n    # Deploy app1 and app2\n    client.deploy_apps(test_config)\n\n    wait_for_condition(\n        lambda: requests.get("http://localhost:8000/app1").text == "wonderful world"\n    )\n    wait_for_condition(\n        lambda: requests.post("http://localhost:8000/app2", json=["ADD", 2]).text\n        == "4 pizzas please!"\n    )\n\n    # Deploy app3\n    new_config = ServeDeploySchema.parse_obj(\n        {\n            "applications": [\n                {\n                    "name": "app3",\n                    "route_prefix": "/app3",\n                    "import_path": pizza_import_path,\n                    "deployments": [\n                        {\n                            "name": "Adder",\n                            "user_config": {\n                                "increment": 3,\n                            },\n                        },\n                    ],\n                },\n            ],\n        }\n    )\n    client.deploy_apps(new_config)\n\n    def check_dead():\n        actors = list_actors(\n            filters=[\n                ("ray_namespace", "=", SERVE_NAMESPACE),\n                ("state", "=", "ALIVE"),\n            ]\n        )\n        for actor in actors:\n            assert "app1" not in actor["name"] and "app2" not in actor["name"]\n        return True\n\n    # Deployments from app1 and app2 should be deleted\n    wait_for_condition(check_dead)\n\n    # App1 and App2 should be gone\n    assert requests.get("http://localhost:8000/app1").status_code != 200\n    assert (\n        requests.post("http://localhost:8000/app2", json=["ADD", 2]).status_code != 200\n    )\n\n    # App3 should be up and running\n    wait_for_condition(\n        lambda: requests.post("http://localhost:8000/app3", json=["ADD", 2]).text\n        == "5 pizzas please!"\n    )\n\n\ndef test_deploy_multi_app_deployments_removed(client: ServeControllerClient):\n    """Test redeploying applications will remove old deployments."""\n\n    world_import_path = "ray.serve.tests.test_config_files.world.DagNode"\n    world_deployments = ["f", "BasicDriver"]\n    pizza_import_path = "ray.serve.tests.test_config_files.pizza.serve_dag"\n    pizza_deployments = [\n        "Adder",\n        "Multiplier",\n        "Router",\n    ]\n    test_config = ServeDeploySchema.parse_obj(\n        {\n            "applications": [\n                {\n                    "name": "app1",\n                    "route_prefix": "/app1",\n                    "import_path": pizza_import_path,\n                },\n            ],\n        }\n    )\n    # Deploy with pizza graph first\n    client.deploy_apps(test_config)\n\n    def check_app(deployments):\n        # Check that the live deployments and actors are what we expect: exactly the\n        # set of deployments in the pizza graph\n        actor_names = {\n            actor["name"] for actor in list_actors(filters=[("state", "=", "ALIVE")])\n        }\n        expected_actor_name_prefixes = {\n            "SERVE_PROXY_ACTOR",\n            "SERVE_CONTROLLER_ACTOR",\n        }.union({f"SERVE_REPLICA::app1#{deployment}" for deployment in deployments})\n        for prefix in expected_actor_name_prefixes:\n            assert any(name.startswith(prefix) for name in actor_names)\n\n        assert {\n            DeploymentID(name=deployment, app_name="app1") for deployment in deployments\n        } == set(ray.get(client._controller._all_running_replicas.remote()).keys())\n        return True\n\n    wait_for_condition(check_app, deployments=pizza_deployments)\n    wait_for_condition(\n        lambda: requests.post("http://localhost:8000/app1", json=["ADD", 2]).text\n        == "4 pizzas please!"\n    )\n\n    # Redeploy with world graph\n    test_config.applications[0].import_path = world_import_path\n    client.deploy_apps(test_config)\n\n    wait_for_condition(check_app, deployments=world_deployments)\n    wait_for_condition(\n        lambda: requests.get("http://localhost:8000/app1").text == "wonderful world"\n    )\n\n\ndef test_controller_recover_and_deploy(client: ServeControllerClient):\n    """Ensure that in-progress deploy can finish even after controller dies."""\n\n    signal = SignalActor.options(name="signal123").remote()\n\n    config_json = {\n        "applications": [\n            {\n                "name": SERVE_DEFAULT_APP_NAME,\n                "import_path": "ray.serve.tests.test_config_files.hangs.app",\n            }\n        ]\n    }\n    config = ServeDeploySchema.parse_obj(config_json)\n    client.deploy_apps(config)\n\n    wait_for_condition(\n        lambda: serve.status().applications["default"].status == "DEPLOYING"\n    )\n    ray.kill(client._controller, no_restart=False)\n\n    signal.send.remote()\n\n    # When controller restarts, it should redeploy config automatically\n    wait_for_condition(\n        lambda: requests.post("http://localhost:8000/").text == "hello world"\n    )\n\n    serve.shutdown()\n    serve.start()\n    client = _get_global_client()\n\n    # Ensure config checkpoint has been deleted\n    assert SERVE_DEFAULT_APP_NAME not in serve.status().applications\n\n\n@pytest.mark.parametrize(\n    "field_to_update",\n    ["import_path", "runtime_env", "ray_actor_options"],\n)\ndef test_deploy_config_update_heavyweight(\n    client: ServeControllerClient, field_to_update: str\n):\n    """Check that replicas are torn down when code updates are made."""\n    config_template = {\n        "applications": [\n            {\n                "name": "default",\n                "import_path": "ray.serve.tests.test_config_files.pid.node",\n                "deployments": [\n                    {\n                        "name": "f",\n                        "autoscaling_config": None,\n                        "user_config": {"name": "alice"},\n                        "ray_actor_options": {"num_cpus": 0.1},\n                    },\n                ],\n            }\n        ]\n    }\n\n    client.deploy_apps(ServeDeploySchema.parse_obj(config_template))\n    wait_for_condition(check_running, timeout=15)\n    pid1, _ = requests.get("http://localhost:8000/f").json()\n\n    if field_to_update == "import_path":\n        config_template["applications"][0][\n            "import_path"\n        ] = "ray.serve.tests.test_config_files.pid.dup_node"\n    elif field_to_update == "runtime_env":\n        config_template["applications"][0]["runtime_env"] = {\n            "env_vars": {"test_var": "test_val"}\n        }\n    elif field_to_update == "ray_actor_options":\n        config_template["applications"][0]["deployments"][0]["ray_actor_options"] = {\n            "num_cpus": 0.2\n        }\n\n    client.deploy_apps(ServeDeploySchema.parse_obj(config_template))\n    wait_for_condition(check_running, timeout=15)\n\n    pids = []\n    for _ in range(4):\n        pids.append(requests.get("http://localhost:8000/f").json()[0])\n    assert pid1 not in pids\n\n\ndef test_update_config_user_config(client: ServeControllerClient):\n    """Check that replicas stay alive when user config is updated."""\n\n    config_template = {\n        "import_path": "ray.serve.tests.test_config_files.pid.node",\n        "deployments": [{"name": "f", "user_config": {"name": "alice"}}],\n    }\n\n    # Deploy first time\n    client.deploy_apps(ServeDeploySchema.parse_obj({"applications": [config_template]}))\n    wait_for_condition(check_running, timeout=15)\n\n    # Query\n    pid1, res = requests.get("http://localhost:8000/f").json()\n    assert res == "alice"\n\n    # Redeploy with updated option\n    config_template["deployments"][0]["user_config"] = {"name": "bob"}\n    client.deploy_apps(ServeDeploySchema.parse_obj({"applications": [config_template]}))\n\n    # Query\n    def check():\n        pids = []\n        for _ in range(4):\n            pid, res = requests.get("http://localhost:8000/f").json()\n            assert res == "bob"\n            pids.append(pid)\n        assert pid1 in pids\n        return True\n\n    wait_for_condition(check)\n\n\ndef test_update_config_graceful_shutdown_timeout(client: ServeControllerClient):\n    """Check that replicas stay alive when graceful_shutdown_timeout_s is updated"""\n    config_template = {\n        "import_path": "ray.serve.tests.test_config_files.pid.node",\n        "deployments": [{"name": "f", "graceful_shutdown_timeout_s": 1000}],\n    }\n\n    # Deploy first time\n    client.deploy_apps(ServeDeploySchema.parse_obj({"applications": [config_template]}))\n    wait_for_condition(check_running, timeout=15)\n    handle = serve.get_app_handle(SERVE_DEFAULT_APP_NAME)\n\n    # Start off with signal ready, and send query\n    handle.send.remote().result()\n    pid1 = handle.remote().result()[0]\n    print("PID of replica after first deployment:", pid1)\n\n    # Redeploy with shutdown timeout set to 5 seconds\n    config_template["deployments"][0]["graceful_shutdown_timeout_s"] = 5\n    client.deploy_apps(ServeDeploySchema.parse_obj({"applications": [config_template]}))\n    wait_for_condition(check_running, timeout=15)\n\n    pid2 = handle.remote().result()[0]\n    assert pid1 == pid2\n    print("PID of replica after redeployment:", pid2)\n\n    # Send blocking query\n    handle.send.remote(clear=True)\n    handle.remote()\n    # Try to delete deployment, should be blocked until the timeout at 5 seconds\n    client.delete_apps([SERVE_DEFAULT_APP_NAME], blocking=False)\n    # Replica should be dead within 10 second timeout, which means\n    # graceful_shutdown_timeout_s was successfully updated lightweightly\n    wait_for_condition(partial(check_deployments_dead, [DeploymentID(name="f")]))\n\n\n@pytest.mark.parametrize("use_max_concurrent_queries", [True, False])\ndef test_update_config_max_ongoing_requests(\n    client: ServeControllerClient, use_max_concurrent_queries\n):\n    """Check that replicas stay alive when max_ongoing_requests is updated."""\n\n    max_ongoing_requests_field_name = (\n        "max_concurrent_queries"\n        if use_max_concurrent_queries\n        else "max_ongoing_requests"\n    )\n    config_template = {\n        "import_path": "ray.serve.tests.test_config_files.pid.node",\n        "deployments": [{"name": "f"}],\n    }\n    config_template["deployments"][0][max_ongoing_requests_field_name] = 1000\n\n    # Deploy first time, max_concurent_queries set to 1000.\n    client.deploy_apps(ServeDeploySchema.parse_obj({"applications": [config_template]}))\n    wait_for_condition(check_running, timeout=15)\n\n    all_replicas = ray.get(client._controller._all_running_replicas.remote())\n    assert len(all_replicas) == 1\n    assert all_replicas[list(all_replicas.keys())[0]][0].max_ongoing_requests == 1000\n\n    handle = serve.get_app_handle(SERVE_DEFAULT_APP_NAME)\n\n    refs = [handle.remote() for _ in range(10)]\n    pids1 = {ref.result()[0] for ref in refs}\n    assert len(pids1) == 1\n\n    # Redeploy with max concurrent queries set to 2.\n    config_template["deployments"][0][max_ongoing_requests_field_name] = 2\n    client.deploy_apps(ServeDeploySchema.parse_obj({"applications": [config_template]}))\n    wait_for_condition(check_running, timeout=15)\n\n    # Verify that the PID of the replica didn\'t change.\n    refs = [handle.remote() for _ in range(10)]\n    pids2 = {ref.result()[0] for ref in refs}\n    assert pids2 == pids1\n\n\ndef test_update_config_health_check_period(client: ServeControllerClient):\n    """Check that replicas stay alive when max_ongoing_requests is updated."""\n\n    config_template = {\n        "import_path": "ray.serve.tests.test_config_files.pid.async_node",\n        "deployments": [{"name": "f", "health_check_period_s": 100}],\n    }\n\n    # Deploy first time, wait for replica running and deployment healthy\n    client.deploy_apps(ServeDeploySchema.parse_obj({"applications": [config_template]}))\n    wait_for_condition(check_running, timeout=15)\n\n    handle = serve.get_app_handle(SERVE_DEFAULT_APP_NAME)\n    pid1 = handle.remote().result()[0]\n\n    # The health check counter shouldn\'t increase beyond any initial health checks\n    # done as part of the replica startup sequence.\n    initial_counter = handle.get_counter.remote(health_check=True).result()\n    time.sleep(5)\n    assert handle.get_counter.remote(health_check=True).result() <= initial_counter + 1\n\n    # Update the deployment\'s health check period to 0.1 seconds.\n    config_template["deployments"][0]["health_check_period_s"] = 0.1\n    client.deploy_apps(ServeDeploySchema.parse_obj({"applications": [config_template]}))\n    wait_for_condition(check_running, timeout=15)\n\n    # Health check counter should now quickly increase due to the shorter period.\n    wait_for_condition(\n        lambda: handle.get_counter.remote(health_check=True).result() >= 30,\n        retry_interval_ms=1000,\n        timeout=10,\n    )\n\n    # Check that it\'s the same replica (it wasn\'t torn down to update the config).\n    pid2 = handle.remote().result()[0]\n    assert pid1 == pid2\n\n\ndef test_update_config_health_check_timeout(client: ServeControllerClient):\n    """Check that replicas stay alive when max_ongoing_requests is updated."""\n\n    # Deploy with a very long initial health_check_timeout_s\n    # Also set small health_check_period_s to make test run faster\n    config_template = {\n        "import_path": "ray.serve.tests.test_config_files.pid.async_node",\n        "deployments": [\n            {\n                "name": "f",\n                "health_check_period_s": 1,\n                "health_check_timeout_s": 1000,\n            }\n        ],\n    }\n\n    # Deploy first time, wait for replica running and deployment healthy\n    client.deploy_apps(ServeDeploySchema.parse_obj({"applications": [config_template]}))\n    wait_for_condition(check_running, timeout=15)\n\n    handle = serve.get_deployment_handle("f", SERVE_DEFAULT_APP_NAME)\n    pid1 = handle.remote().result()[0]\n\n    # Redeploy with health check timeout reduced to 1 second\n    config_template["deployments"][0]["health_check_timeout_s"] = 1\n    client.deploy_apps(ServeDeploySchema.parse_obj({"applications": [config_template]}))\n    wait_for_condition(check_running, timeout=15)\n\n    # Check that it\'s the same replica, it didn\'t get teared down\n    # (needs to be done before the tests below because the replica will be marked\n    # unhealthy then stopped and restarted)\n    pid2 = handle.remote().result()[0]\n    assert pid1 == pid2\n\n    # Block in health check\n    handle.send.remote(clear=True, health_check=True).result()\n    wait_for_condition(\n        lambda: serve.status()\n        .applications[SERVE_DEFAULT_APP_NAME]\n        .deployments["f"]\n        .status\n        == DeploymentStatus.UNHEALTHY\n    )\n\n\ndef test_update_autoscaling_config(client: ServeControllerClient):\n    signal = SignalActor.options(name="signal123").remote()\n\n    config_template = {\n        "import_path": "ray.serve.tests.test_config_files.get_signal.app",\n        "deployments": [\n            {\n                "name": "A",\n                "autoscaling_config": {\n                    "target_ongoing_requests": 1,\n                    "min_replicas": 1,\n                    "max_replicas": 10,\n                    "metrics_interval_s": 15,\n                    "upscale_delay_s": 0.5,\n                    "downscale_delay_s": 0.5,\n                    "look_back_period_s": 2,\n                },\n                "graceful_shutdown_timeout_s": 1,\n            }\n        ],\n    }\n\n    print(time.ctime(), "Deploying pid application.")\n    client.deploy_apps(ServeDeploySchema.parse_obj({"applications": [config_template]}))\n    wait_for_condition(check_running, timeout=15)\n    print(time.ctime(), "Application is RUNNING.")\n\n    print(time.ctime(), "Sending 1 initial unblocked request.")\n    h = serve.get_app_handle(SERVE_DEFAULT_APP_NAME)\n    signal.send.remote()\n    h.remote().result()\n\n    print(time.ctime(), "Sending 5 blocked requests. Deployment should NOT scale up.")\n    signal.send.remote(clear=True)\n    [h.remote() for _ in range(5)]\n    with pytest.raises(RuntimeError, match="timeout"):\n        wait_for_condition(check_num_replicas_gte, name="A", target=2)\n\n    print(time.ctime(), "Redeploying with `metrics_interval_s` updated to 0.5s.")\n    config_template["deployments"][0]["autoscaling_config"]["metrics_interval_s"] = 0.5\n    client.deploy_apps(ServeDeploySchema.parse_obj({"applications": [config_template]}))\n\n    wait_for_condition(check_num_replicas_gte, name="A", target=2)\n    print(time.ctime(), "Number of replicas scaled up. Unblocking signal.")\n    signal.send.remote()\n\n    wait_for_condition(check_num_replicas_lte, name="A", target=1)\n    print(time.ctime(), "Number of replicas dropped back down to 1.")\n\n\ndef test_deploy_separate_runtime_envs(client: ServeControllerClient):\n    """Deploy two applications with separate runtime envs."""\n\n    config_template = {\n        "applications": [\n            {\n                "name": "app1",\n                "route_prefix": "/app1",\n                "import_path": "conditional_dag.serve_dag",\n                "runtime_env": {\n                    "working_dir": TEST_DAG_PINNED_URI,\n                },\n            },\n            {\n                "name": "app2",\n                "route_prefix": "/app2",\n                "import_path": "hello_world.app",\n                "runtime_env": {\n                    "working_dir": TEST_RUNTIME_ENV_PINNED_URI,\n                },\n            },\n        ],\n    }\n\n    client.deploy_apps(ServeDeploySchema(**config_template))\n\n    wait_for_condition(\n        check_endpoint,\n        endpoint="app1",\n        json=["ADD", 2],\n        expected="0 pizzas please!",\n        timeout=90,\n    )\n\n    wait_for_condition(\n        lambda: requests.post("http://localhost:8000/app2").text == "Hello world!"\n    )\n\n\ndef test_deploy_one_app_failed(client: ServeControllerClient):\n    """Deploy two applications with separate runtime envs."""\n\n    world_import_path = "ray.serve.tests.test_config_files.world.DagNode"\n    fail_import_path = "ray.serve.tests.test_config_files.fail.node"\n    config_template = {\n        "applications": [\n            {\n                "name": "app1",\n                "route_prefix": "/app1",\n                "import_path": world_import_path,\n            },\n            {\n                "name": "app2",\n                "route_prefix": "/app2",\n                "import_path": fail_import_path,\n            },\n        ],\n    }\n\n    client.deploy_apps(ServeDeploySchema(**config_template))\n\n    wait_for_condition(\n        lambda: requests.post("http://localhost:8000/app1").text == "wonderful world"\n    )\n\n    wait_for_condition(\n        lambda: serve.status().applications["app1"].status == ApplicationStatus.RUNNING\n        and serve.status().applications["app2"].status\n        == ApplicationStatus.DEPLOY_FAILED\n    )\n\n\ndef test_deploy_with_route_prefix_conflict(client: ServeControllerClient):\n    world_import_path = "ray.serve.tests.test_config_files.world.DagNode"\n    pizza_import_path = "ray.serve.tests.test_config_files.pizza.serve_dag"\n    test_config = {\n        "applications": [\n            {\n                "name": "app1",\n                "route_prefix": "/app1",\n                "import_path": world_import_path,\n            },\n            {\n                "name": "app2",\n                "route_prefix": "/app2",\n                "import_path": pizza_import_path,\n            },\n        ],\n    }\n\n    client.deploy_apps(ServeDeploySchema(**test_config))\n\n    wait_for_condition(\n        lambda: requests.get("http://localhost:8000/app1").text == "wonderful world"\n    )\n    wait_for_condition(\n        lambda: requests.post("http://localhost:8000/app2", json=["ADD", 2]).text\n        == "4 pizzas please!"\n    )\n\n    # Buffer time\n    time.sleep(1)\n\n    test_config["applications"][1] = {\n        "name": "app3",\n        "route_prefix": "/app2",\n        "import_path": world_import_path,\n    }\n\n    client.deploy_apps(ServeDeploySchema(**test_config))\n\n    def check():\n        serve_details = ServeInstanceDetails(\n            **ray.get(client._controller.get_serve_instance_details.remote())\n        )\n        app1_running = (\n            "app1" in serve_details.applications\n            and serve_details.applications["app1"].status == "RUNNING"\n        )\n        app3_running = (\n            "app3" in serve_details.applications\n            and serve_details.applications["app3"].status == "RUNNING"\n        )\n        app2_gone = "app2" not in serve_details.applications\n        return app1_running and app3_running and app2_gone\n\n    wait_for_condition(check)\n\n    # app1 and app3 should be up and running\n    wait_for_condition(\n        lambda: requests.get("http://localhost:8000/app1").text == "wonderful world"\n    )\n    wait_for_condition(\n        lambda: requests.get("http://localhost:8000/app2").text == "wonderful world"\n    )\n\n\ndef test_deploy_multi_app_deleting(client: ServeControllerClient):\n    """Test deleting an application by removing from config."""\n\n    config = ServeDeploySchema.parse_obj(get_test_deploy_config())\n    client.deploy_apps(config)\n    check_multi_app()\n\n    # Delete app2\n    del config.applications[1]\n    client.deploy_apps(config)\n\n    # Fetch details immediately afterwards, should parse correctly\n    details = ray.get(client._controller.get_serve_instance_details.remote())\n    ServeInstanceDetails(**details)\n    # We don\'t enforce that the state is deleting here because that could cause\n    # flaky test performance. The app could have been deleted by the time of query\n    assert (\n        "app2" not in details["applications"]\n        or details["applications"]["app2"]["status"] == ApplicationStatus.DELETING\n    )\n\n    info_valid = True\n\n    def check_app_status():\n        global info_valid\n        try:\n            # Fetch details, should always parse correctly\n            details = ray.get(client._controller.get_serve_instance_details.remote())\n            ServeInstanceDetails(**details)\n            return (\n                details["applications"]["app1"]["status"] == ApplicationStatus.RUNNING\n                and "app2" not in details["applications"]\n            )\n        except Exception:\n            info_valid = False\n\n    wait_for_condition(check_app_status)\n    # Check that all all details fetched from controller parsed correctly\n    assert info_valid\n\n\ndef test_deploy_nonexistent_deployment(client: ServeControllerClient):\n    """Apply a config that lists a deployment that doesn\'t exist in the application.\n    The error message should be descriptive.\n    """\n\n    config = ServeDeploySchema.parse_obj(get_test_deploy_config())\n    # Change names to invalid names that don\'t contain "deployment" or "application"\n    config.applications[1].name = "random1"\n    config.applications[1].deployments[0].name = "random2"\n    client.deploy_apps(config)\n\n    def check_app_message():\n        details = ray.get(client._controller.get_serve_instance_details.remote())\n        # The error message should be descriptive\n        # e.g. no deployment "x" in application "y"\n        return (\n            "application" in details["applications"]["random1"]["message"]\n            and "deployment" in details["applications"]["random1"]["message"]\n        )\n\n    wait_for_condition(check_app_message)\n\n\ndef test_deploy_with_no_applications(client: ServeControllerClient):\n    """Deploy an empty list of applications, serve should just be started."""\n\n    config = ServeDeploySchema.parse_obj({"applications": []})\n    client.deploy_apps(config)\n\n    def serve_running():\n        ServeInstanceDetails.parse_obj(\n            ray.get(client._controller.get_serve_instance_details.remote())\n        )\n        actors = list_actors(\n            filters=[\n                ("ray_namespace", "=", SERVE_NAMESPACE),\n                ("state", "=", "ALIVE"),\n            ]\n        )\n        actor_names = [actor["class_name"] for actor in actors]\n        return "ServeController" in actor_names and "ProxyActor" in actor_names\n\n    wait_for_condition(serve_running)\n\n\ndef test_deployments_not_listed_in_config(client: ServeControllerClient):\n    """Apply a config without the app\'s deployments listed. The deployments should\n    not redeploy.\n    """\n\n    config = {\n        "applications": [{"import_path": "ray.serve.tests.test_config_files.pid.node"}]\n    }\n    client.deploy_apps(ServeDeploySchema(**config))\n    wait_for_condition(check_running, timeout=15)\n    pid1, _ = requests.get("http://localhost:8000/").json()\n\n    # Redeploy the same config (with no deployments listed)\n    client.deploy_apps(ServeDeploySchema(**config))\n    wait_for_condition(check_running, timeout=15)\n\n    # It should be the same replica actor\n    pids = []\n    for _ in range(4):\n        pids.append(requests.get("http://localhost:8000/").json()[0])\n    assert all(pid == pid1 for pid in pids)\n\n\ndef test_get_app_handle(client: ServeControllerClient):\n    config = ServeDeploySchema.parse_obj(get_test_deploy_config())\n    client.deploy_apps(config)\n    check_multi_app()\n\n    handle_1 = serve.get_app_handle("app1")\n    handle_2 = serve.get_app_handle("app2")\n    assert handle_1.route.remote("ADD", 2).result() == "4 pizzas please!"\n    assert handle_2.route.remote("ADD", 2).result() == "5 pizzas please!"\n\n\n@pytest.mark.parametrize("heavyweight", [True, False])\ndef test_deploy_lightweight_multiple_route_prefix(\n    client: ServeControllerClient, heavyweight: bool\n):\n    """If user deploys a config that sets route prefix for a non-ingress deployment,\n    the deploy should fail.\n    """\n\n    config = {\n        "applications": [\n            {\n                "name": "default",\n                "import_path": "ray.serve.tests.test_config_files.world.DagNode",\n            }\n        ]\n    }\n    client.deploy_apps(ServeDeploySchema(**config))\n\n    def check():\n        assert requests.post("http://localhost:8000/").text == "wonderful world"\n        return True\n\n    wait_for_condition(check)\n\n    # Add route prefix for non-ingress deployment\n    config["applications"][0]["deployments"] = [{"name": "f", "route_prefix": "/"}]\n    if heavyweight:\n        # Trigger re-build of the application\n        config["applications"][0]["runtime_env"] = {"env_vars": {"test": "3"}}\n    client.deploy_apps(ServeDeploySchema(**config))\n\n    def check_failed():\n        s = serve.status().applications["default"]\n        assert s.status == ApplicationStatus.DEPLOY_FAILED\n        assert "Found multiple route prefixes" in s.message\n        return True\n\n    wait_for_condition(check_failed)\n\n    # Check 10 more times to make sure the status doesn\'t oscillate\n    for _ in range(10):\n        s = serve.status().applications["default"]\n        assert s.status == ApplicationStatus.DEPLOY_FAILED\n        assert "Found multiple route prefixes" in s.message\n        time.sleep(0.1)\n\n\n@pytest.mark.parametrize("rebuild", [True, False])\ndef test_redeploy_old_config_after_failed_deployment(\n    client: ServeControllerClient, rebuild\n):\n    """\n    1. Deploy application which succeeds.\n    2. Redeploy application with an import path that fails.\n    3. Redeploy the exact same config from step 1.\n\n    Verify that step 3 succeeds and the application returns to running state.\n    """\n\n    app_config = {\n        "name": "default",\n        "import_path": "ray.serve.tests.test_config_files.world.DagNode",\n    }\n    client.deploy_apps(ServeDeploySchema(**{"applications": [app_config]}))\n\n    def check_application_running():\n        status = serve.status().applications["default"]\n        assert status.status == "RUNNING"\n        assert requests.post("http://localhost:8000/").text == "wonderful world"\n        return True\n\n    wait_for_condition(check_application_running)\n\n    # Change config so that redeploy will error\n    new_app_config = copy(app_config)\n    if rebuild:\n        # New import path will cause an error upon importing app\n        new_app_config[\n            "import_path"\n        ] = "ray.serve.tests.test_config_files.import_error.app"\n        err_msg = "ZeroDivisionError"\n    else:\n        # Trying to add a route prefix for non-ingress deployment will fail\n        new_app_config["deployments"] = [{"name": "f", "route_prefix": "/"}]\n        err_msg = "Found multiple route prefixes"\n    client.deploy_apps(ServeDeploySchema(**{"applications": [new_app_config]}))\n\n    def check_deploy_failed(message):\n        status = serve.status().applications["default"]\n        assert status.status == "DEPLOY_FAILED"\n        assert message in status.message\n        return True\n\n    wait_for_condition(check_deploy_failed, message=err_msg)\n\n    # Redeploy old config\n    client.deploy_apps(ServeDeploySchema(**{"applications": [app_config]}))\n\n    wait_for_condition(check_application_running)\n\n\ndef test_change_route_prefix(client: ServeControllerClient):\n    # Deploy application with route prefix /old\n    app_config = {\n        "name": "default",\n        "route_prefix": "/old",\n        "import_path": "ray.serve.tests.test_config_files.pid.node",\n    }\n    client.deploy_apps(ServeDeploySchema(**{"applications": [app_config]}))\n\n    wait_for_condition(check_running)\n    pid1 = requests.get("http://localhost:8000/old").json()[0]\n\n    # Redeploy application with route prefix /new.\n    app_config["route_prefix"] = "/new"\n    client.deploy_apps(ServeDeploySchema(**{"applications": [app_config]}))\n\n    # Check that the old route is gone and the response from the new route\n    # has the same PID (replica wasn\'t restarted).\n    def check_switched():\n        # Old route should be gone\n        resp = requests.get("http://localhost:8000/old")\n        assert "Path \'/old\' not found." in resp.text\n\n        # Response from new route should be same PID\n        pid2 = requests.get("http://localhost:8000/new").json()[0]\n        assert pid2 == pid1\n        return True\n\n    wait_for_condition(check_switched)\n\n\ndef test_num_replicas_auto(client: ServeControllerClient):\n    """Test `num_replicas="auto"`."""\n\n    signal = SignalActor.options(name="signal123").remote()\n\n    config_template = {\n        "import_path": "ray.serve.tests.test_config_files.get_signal.app",\n        "deployments": [\n            {\n                "name": "A",\n                "num_replicas": "auto",\n                "autoscaling_config": {\n                    "look_back_period_s": 2.0,\n                    "metrics_interval_s": 1.0,\n                    "upscale_delay_s": 1.0,\n                },\n                "graceful_shutdown_timeout_s": 1,\n            }\n        ],\n    }\n\n    print(time.ctime(), "Deploying pid application.")\n    client.deploy_apps(ServeDeploySchema.parse_obj({"applications": [config_template]}))\n    wait_for_condition(check_running, timeout=15)\n    print(time.ctime(), "Application is RUNNING.")\n    check_num_replicas_eq("A", 1)\n\n    app_details = client.get_serve_details()["applications"][SERVE_DEFAULT_APP_NAME]\n    deployment_config = app_details["deployments"]["A"]["deployment_config"]\n    # Set by `num_replicas="auto"`\n    assert "num_replicas" not in deployment_config\n    assert deployment_config["max_ongoing_requests"] == 5\n    assert deployment_config["autoscaling_config"] == {\n        # Set by `num_replicas="auto"`\n        "target_ongoing_requests": 2.0,\n        "target_num_ongoing_requests_per_replica": 2.0,\n        "min_replicas": 1,\n        "max_replicas": 100,\n        # Overrided by `autoscaling_config`\n        "look_back_period_s": 2.0,\n        "metrics_interval_s": 1.0,\n        "upscale_delay_s": 1.0,\n        # Untouched defaults\n        "downscale_delay_s": 600.0,\n        "upscale_smoothing_factor": None,\n        "downscale_smoothing_factor": None,\n        "upscaling_factor": None,\n        "downscaling_factor": None,\n        "smoothing_factor": 1.0,\n        "initial_replicas": None,\n    }\n\n    h = serve.get_app_handle(SERVE_DEFAULT_APP_NAME)\n    for i in range(3):\n        [h.remote() for _ in range(2)]\n\n        def check_num_waiters(target: int):\n            assert ray.get(signal.cur_num_waiters.remote()) == target\n            return True\n\n        wait_for_condition(check_num_waiters, target=2 * (i + 1))\n        print(time.time(), f"Number of waiters on signal reached {2*(i+1)}.")\n        wait_for_condition(check_num_replicas_eq, name="A", target=i + 1)\n        print(time.time(), f"Confirmed number of replicas are at {i+1}.")\n\n    signal.send.remote()\n\n\ndef check_log_file(log_file: str, expected_regex: list):\n    with open(log_file, "r") as f:\n        s = f.read()\n        print(s)\n        for regex in expected_regex:\n            assert re.findall(regex, s) != [], f"Did not find pattern \'{regex}\' in {s}"\n    return True\n\n\nclass TestDeploywithLoggingConfig:\n    def get_deploy_config(self, model_within_logging_config: bool = False):\n        if model_within_logging_config:\n            path = "ray.serve.tests.test_config_files.logging_config_test.model2"\n        else:\n            path = "ray.serve.tests.test_config_files.logging_config_test.model"\n        return {\n            "applications": [\n                {\n                    "name": "app1",\n                    "route_prefix": "/app1",\n                    "import_path": path,\n                },\n            ],\n        }\n\n    @pytest.mark.parametrize("encoding_type", ["TEXT", "JSON"])\n    def test_deploy_app_with_application_logging_config(\n        self, client: ServeControllerClient, encoding_type: str\n    ):\n        """Deploy application with application logging config"""\n        config_dict = self.get_deploy_config()\n\n        config_dict["applications"][0]["logging_config"] = {\n            "encoding": encoding_type,\n        }\n        config = ServeDeploySchema.parse_obj(config_dict)\n        client.deploy_apps(config)\n        wait_for_condition(\n            lambda: requests.post("http://localhost:8000/app1").status_code == 200\n        )\n\n        resp = requests.post("http://localhost:8000/app1").json()\n\n        replica_id = resp["replica"].split("#")[-1]\n        if encoding_type == "JSON":\n            expected_log_regex = [f\'"replica": "{replica_id}", \']\n        else:\n            expected_log_regex = [f".*{replica_id}.*"]\n        check_log_file(resp["log_file"], expected_log_regex)\n\n    @pytest.mark.parametrize("encoding_type", ["TEXT", "JSON"])\n    def test_deploy_app_with_deployment_logging_config(\n        self, client: ServeControllerClient, encoding_type: str\n    ):\n        """Deploy application with deployment logging config inside the yaml"""\n        config_dict = self.get_deploy_config()\n\n        config_dict["applications"][0]["deployments"] = [\n            {\n                "name": "Model",\n                "logging_config": {\n                    "encoding": encoding_type,\n                },\n            },\n        ]\n        config = ServeDeploySchema.parse_obj(config_dict)\n        client.deploy_apps(config)\n        wait_for_condition(\n            lambda: requests.post("http://localhost:8000/app1").status_code == 200\n        )\n\n        resp = requests.post("http://localhost:8000/app1").json()\n\n        replica_id = resp["replica"].split("#")[-1]\n        if encoding_type == "JSON":\n            expected_log_regex = [f\'"replica": "{replica_id}", \']\n        else:\n            expected_log_regex = [f".*{replica_id}.*"]\n        check_log_file(resp["log_file"], expected_log_regex)\n\n    def test_deploy_app_with_deployment_logging_config_in_code(\n        self,\n        client: ServeControllerClient,\n    ):\n        """Deploy application with deployment logging config inside the code"""\n        config_dict = self.get_deploy_config(model_within_logging_config=True)\n        config = ServeDeploySchema.parse_obj(config_dict)\n        client.deploy_apps(config)\n        wait_for_condition(\n            lambda: requests.post("http://localhost:8000/app1").status_code == 200\n        )\n        resp = requests.post("http://localhost:8000/app1").json()\n        check_log_file(resp["log_file"], [".*this_is_debug_info.*"])\n\n    def test_overwritting_logging_config(self, client: ServeControllerClient):\n        """Overwrite the default logging config with application logging config"""\n        config_dict = self.get_deploy_config()\n        config = ServeDeploySchema.parse_obj(config_dict)\n        client.deploy_apps(config)\n\n        wait_for_condition(\n            lambda: requests.post("http://localhost:8000/app1").status_code == 200\n        )\n\n        def get_replica_info_format(replica_id: ReplicaID) -> str:\n            app_name = replica_id.deployment_id.app_name\n            deployment_name = replica_id.deployment_id.name\n            return f"{app_name}_{deployment_name} {replica_id.unique_id}"\n\n        # By default, log level is "INFO"\n        r = requests.post("http://localhost:8000/app1")\n        r.raise_for_status()\n        request_id = r.headers["X-Request-Id"]\n        replica_id = ReplicaID.from_full_id_str(r.json()["replica"])\n\n        # Make sure \'model_debug_level\' log content does not exist.\n        with pytest.raises(AssertionError):\n            check_log_file(r.json()["log_file"], [".*this_is_debug_info.*"])\n\n        # Check the log formatting.\n        check_log_file(\n            r.json()["log_file"],\n            f" {get_replica_info_format(replica_id)} {request_id} ",\n        )\n\n        # Set log level to "DEBUG"\n        config_dict["applications"][0]["logging_config"] = {\n            "log_level": "DEBUG",\n        }\n        config = ServeDeploySchema.parse_obj(config_dict)\n        client.deploy_apps(config)\n\n        wait_for_condition(\n            lambda: requests.post("http://localhost:8000/app1").status_code == 200\n            and requests.post("http://localhost:8000/app1").json()["log_level"]\n            == logging.DEBUG,\n        )\n        r = requests.post("http://localhost:8000/app1")\n        r.raise_for_status()\n        request_id = r.headers["X-Request-Id"]\n        replica_id = ReplicaID.from_full_id_str(r.json()["replica"])\n        check_log_file(\n            r.json()["log_file"],\n            [\n                # Check for DEBUG-level log statement.\n                ".*this_is_debug_info.*",\n                # Check that the log formatting has remained the same.\n                f" {get_replica_info_format(replica_id)} {request_id} ",\n            ],\n        )\n\n    def test_not_overwritting_logging_config_in_yaml(\n        self, client: ServeControllerClient\n    ):\n        """Deployment logging config in yaml should not be overwritten\n        by application logging config.\n        """\n        config_dict = self.get_deploy_config()\n        config_dict["applications"][0]["deployments"] = [\n            {\n                "name": "Model",\n                "logging_config": {\n                    "log_level": "DEBUG",\n                },\n            },\n        ]\n        config_dict["applications"][0]["logging_config"] = {\n            "log_level": "INFO",\n        }\n\n        config = ServeDeploySchema.parse_obj(config_dict)\n        client.deploy_apps(config)\n        wait_for_condition(\n            lambda: requests.post("http://localhost:8000/app1").status_code == 200\n        )\n        resp = requests.post("http://localhost:8000/app1").json()\n        check_log_file(resp["log_file"], [".*this_is_debug_info.*"])\n\n    def test_not_overwritting_logging_config_in_code(\n        self, client: ServeControllerClient\n    ):\n        """Deployment logging config in code should not be overwritten\n        by application logging config.\n        """\n        config_dict = self.get_deploy_config(model_within_logging_config=True)\n        config_dict["applications"][0]["logging_config"] = {\n            "log_level": "INFO",\n        }\n\n        config = ServeDeploySchema.parse_obj(config_dict)\n        client.deploy_apps(config)\n        wait_for_condition(\n            lambda: requests.post("http://localhost:8000/app1").status_code == 200\n        )\n        resp = requests.post("http://localhost:8000/app1").json()\n        check_log_file(resp["log_file"], [".*this_is_debug_info.*"])\n\n    def test_logs_dir(self, client: ServeControllerClient):\n\n        config_dict = self.get_deploy_config()\n        config_dict["applications"][0]["logging_config"] = {\n            "log_level": "DEBUG",\n        }\n        config = ServeDeploySchema.parse_obj(config_dict)\n        client.deploy_apps(config)\n        wait_for_condition(\n            lambda: requests.post("http://localhost:8000/app1").status_code == 200\n        )\n        resp = requests.get("http://127.0.0.1:8000/app1").json()\n\n        # Construct a new path\n        # "/tmp/ray/session_xxx/logs/serve/new_dir"\n        paths = resp["log_file"].split("/")\n        paths[-1] = "new_dir"\n        new_log_dir = "/".join(paths)\n\n        config_dict["applications"][0]["logging_config"] = {\n            "log_level": "DEBUG",\n            "logs_dir": new_log_dir,\n        }\n        config = ServeDeploySchema.parse_obj(config_dict)\n        client.deploy_apps(config)\n        wait_for_condition(\n            lambda: requests.post("http://localhost:8000/app1").status_code == 200\n            and "new_dir"\n            in requests.get("http://127.0.0.1:8000/app1").json()["log_file"]\n        )\n        resp = requests.get("http://127.0.0.1:8000/app1").json()\n        # log content should be redirected to new file\n        check_log_file(resp["log_file"], [".*this_is_debug_info.*"])\n\n    @pytest.mark.parametrize("enable_access_log", [True, False])\n    def test_access_log(self, client: ServeControllerClient, enable_access_log: bool):\n\n        config_dict = self.get_deploy_config()\n        config_dict["applications"][0]["logging_config"] = {\n            "enable_access_log": enable_access_log,\n        }\n        config = ServeDeploySchema.parse_obj(config_dict)\n        client.deploy_apps(config)\n        wait_for_condition(\n            lambda: requests.post("http://localhost:8000/app1").status_code == 200\n        )\n        resp = requests.get("http://127.0.0.1:8000/app1")\n        assert resp.status_code == 200\n        resp = resp.json()\n        if enable_access_log:\n            check_log_file(resp["log_file"], [".*this_is_access_log.*"])\n        else:\n            with pytest.raises(AssertionError):\n                check_log_file(resp["log_file"], [".*this_is_access_log.*"])\n\n\nif __name__ == "__main__":\n    sys.exit(pytest.main(["-v", "-s", __file__]))\n',
        }
